
import Checker from 'vux/src/components/checker/checker.vue'
import Search from 'vux/src/components/search/index.vue'
import Cell from 'vux/src/components/cell/index.vue'
import Checklist from 'vux/src/components/checklist/index.vue'
import CheckerItem from 'vux/src/components/checker/checker-item.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import XTextarea from 'vux/src/components/x-textarea/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,commonPost,commonDown } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import downPath from '../assets/js/getData'
import lisUtils from '../assets/js/units.js'
export default {
data (){
return {
showContent001: true,
showContent002: true,
showContent003: true,
showContent004: true,
showContent005: true,
showContent006: true,
showLoading: false,
show1: false,
text: '',
showMenus: false,
ticketDetail: {},
showFile: false,
logFlag: false,
workFlowTaskInstanceList: [],
isGetLog: false,
ticketId: this.$route.query.ticketId
}
},
created (){
this.getDetailMsg()

},
mounted (){},
filters: {
setProjectType (val){
if(val == '1'){
return '架空线路工程'
}else if(val == '2'){
return '变电工程'
}else{
return val
}
},
setState (val){
if(val){
if(val == '1'){//1/提交2/退回3/终止4/撤回
return '通过'
}else if(val == '2'){
return '驳回'
}else if(val == '3'){
return '终止'
}else if(val == '4'){
return '撤回'
}
}else{
return ''
}
}
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
Checklist,
Cell,
Search
},
methods: {
back() {
this.$router.go(-1)
},

showLog (){
if(this.isGetLog){
this.logFlag = true
}else{
this.getLog()
}
},

getLog (){
let _this = this
_this.showLoading = true
let params = {
businessId:_this.ticketDetail.id,
flowId:_this.ticketDetail.flowId
}
let urls = 'workticket/workTicketInfo/selectFlowTaskInstanceList'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.workFlowTaskInstanceList = res.data
_this.isGetLog = true
_this.logFlag = true
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

previewPdf (item){
let _this = this
_this.showLoading = true
let params = {
id: item.id
}
let urls = 'program/youotech/download'
commonDown(urls,params,function(res){
_this.showLoading = false
let blob = new Blob([res], {
type: ''
})
let objectUrl = URL.createObjectURL(blob)
_this.filePath = 'static/pdf/web/viewer.html?file=' + objectUrl
_this.showFile = true

})
},
getDetailMsg (){
let _this = this
_this.showLoading = true
let params = {
id: _this.ticketId

}
let urls = 'workticket/workTicketInfo/selectWorkTicketDetail'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
let item = {
position: '',
temp: ''
}
for(let i in res.data.workTicketPartSiteList){
item.position = '经度：' + res.data.workTicketPartSiteList[i].longitude + '纬度：' + res.data.workTicketPartSiteList[i].latitude
}
if(res.data.workTypeName.indexOf('A票') > 0 || res.data.workTypeName.indexOf('A票') == 0){
item.temp = 'A'
}else{
item.temp = 'B'
}
res.data = Object.assign(res.data,item)
_this.ticketDetail = res.data
_this.getPeopNamePic(res.data.workTicketSignPicList)
_this.getTicketPeopType(res.data.ticketTypeId,res.data.workTicketPeopDivisionList)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

getTicketPeopType (id,peopList){
let _this = this
let params = {
ticketTypeId: id
}
let urls = 'workticket/workTicketInfo/selectWorkTikcetPeopType'
commonGet(urls,params,function(res){
if(res.code == 200){
let item = {
workTicketPeop: []
}
for(let i in res.data){
res.data[i].peopName = ''
for(let j in peopList){
if(res.data[i].typeName == peopList[j].typeName){
res.data[i].peopName = res.data[i].peopName + ',' + peopList[j].peopName
}
}
res.data[i].peopName = res.data[i].peopName.substr(1)
}
item.workTicketPeop = res.data
_this.ticketDetail = Object.assign(_this.ticketDetail,item)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

getPeopNamePic (picIdList){
let _this = this
let idList = picIdList.map(item => {
return item.picPath
})
if(idList.length==0){
return
}
let params = {
ids: idList.join(',')
}

let urls = 'v1/files/batch'
commonGet(urls,params,function(res){
for(let i in _this.ticketDetail.workTicketSignPicList){
for(let j in res.data){
if(_this.ticketDetail.workTicketSignPicList[i].picPath == res.data[j].id){








_this.$set(_this.ticketDetail.workTicketSignPicList[i],'src',res.data[j].url)
_this.$set(_this.ticketDetail.workTicketSignPicList[i],'path',res.data[j].path)
}
}
}
console.log(_this.ticketDetail.workTicketSignPicList)
})
}
},
watch: {

}
}



