
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import Tab from 'vux/src/components/tab/tab.vue'
import TabItem from 'vux/src/components/tab/tab-item.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import Store from '../store/store'
import Session from '../store/session'
import {commonGet, commonPosts, commonPost} from '../assets/js/getData'
import { mapGetters } from 'vuex'
import manageWkg from '@/page/workManage_wkg'
import manageKg from '@/page/workManage_kg'
import manageZt from '@/page/workManage_zt'
import manageWg from '@/page/workManage_wg'
export default {
directives: {
TransferDom
},
components: {
XHeader,
Group,
PopupPicker,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Tab,
TabItem,
manageWkg,
manageKg,
manageZt,
manageWg,
},
data() {
return {
isManage: true,
unitFlag: false,
proFlag: false,
searchFlag: false,
showLoading: false,
show1: false,
text: '',
seachSpanList: [
{text: '全部',id: '',isChoose: true},
{text: '一级',id: '1',isChoose: false},
{text: '二级',id: '2',isChoose: false},
{text: '三级',id: '3',isChoose: false},
{text: '四级',id: '4',isChoose: false},
],
seachId: '',
unitData: [],//建管单位
projectData: [],//工程
unitId: [],
unitName: '',
projectName: '',
projectId: [],
ticketType: 0,
list2: [
{name: '未开工',value: '0'},
{name: '开工',value: '1'},
{name: '暂停',value: '2'},
{name: '完工',value: '3'},
],
demo2: '0',
peopList: Session.fetch('authorizationList'),
showWhat: 'manage',
ticketId: ''
}
},
computed:{
},
created() {
this.$store.commit('setShowTab',true)
this.initPage()
},
activated (){
if(this.manageAlive){
this.$store.commit('setShowTab',true)
}else{
this.$store.commit('setShowTab',true)
Object.assign(this.$data, this.$options.data())
this.initPage()
this.$store.commit('setManageAlive',true)
}
},
computed:{
...mapGetters({
manageAlive: 'getManageAlive'
})
},
mounted() {},
methods: {
showTicketDetail (ticketId,type){
this.ticketId = ticketId
if(type == '1'){
this.$router.push({path: '/workManage_ticketDetail',query: {ticketId: ticketId}})
}else{
this.$router.push({path: '/workManage_unit',query: {ticketId: ticketId}})
}
},
initPage (){
if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.workTicketLevel == 22) {
this.getOrg()
this.unitFlag = false
}else if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 11){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
}else{
if(!this.peopList.project){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.unitData = [{
name:this.peopList.project.unitName,
value:this.peopList.project.unitId.toString()
}]
this.unitId = [this.peopList.project.unitId.toString()]
this.unitFlag = true
this.proFlag = true
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
}
}
this.getNumber()
},

getNumber (){
let _this = this
let params = {
projectId: _this.projectId.length>0 ? _this.projectId[0]: '',
buildUnitId: _this.unitId.length>0 ? _this.unitId[0]: '',
afterRisk: _this.seachId,
}
let urls = 'saferisk/risk/work/gk/count'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.list2[0].name = '未开工(' + res.data.wkg + ')'
_this.list2[1].name = '开工(' + res.data.kg + ')'
_this.list2[2].name = '暂停(' + res.data.pause + ')'
_this.list2[3].name = '已完工(' + res.data.ytg + ')'
}
})
},

getOrg (){
let _this = this
let params = {

}
let urls = 'pms/api/v1/units/list/org/current-user'
commonGet(urls,params,function(res){
if(!res.status && res){
_this.unitData = res.map((item) => {
return {name: item.name,value: item.id.toString()}
})



}
})
},
changeUnit (){
this.getProjects()
},

getProjects (){
let _this = this
let params = {

}
_this.projectData = []
let urls = 'pms/api/v1/unit_projects/list/unit/'+_this.unitId[0]
commonGet(urls,params,function(res){
if(!res.status && res){



for(let i in res){
if(res[i].pid != '0'){
let item = {name: res[i].name,value: res[i].id.toString()}
_this.projectData.push(item)
}
}



}
})
},

clickSpan (id){
for(let i in this.seachSpanList){
if(id != this.seachSpanList[i].id){
this.seachSpanList[i].isChoose = false
}else{
this.seachSpanList[i].isChoose = true
this.seachId = this.seachSpanList[i].id
}
}
},
tabClick (index){
this.ticketType = index
},

query (){
this.searchFlag = false









if(this.$refs.manageWkg) this.$refs.manageWkg.query()
if(this.$refs.manageKg) this.$refs.manageKg.query()
if(this.$refs.manageZt) this.$refs.manageZt.query()
if(this.$refs.manageWg) this.$refs.manageWg.query()
this.getNumber()
},
cancel (){
this.searchFlag = false
},

showSearch (){
this.searchFlag = !this.searchFlag
},
back (){
this.$router.go(-1)
}
}
}



