

import Vue from 'vue'
import VueRouter from 'vue-router'
import App from './App'
import router from './router'
import store from './store'
import '@/assets/css/common.css'
import '@/assets/css/index.css'
import '@/assets/js/size'
import '@/assets/js/public'
import lisUtils from '@/assets/js/units.js'
import LoadingPlugin from 'vux/src/plugins/loading/index.js'
import ConfirmPlugin from 'vux/src/plugins/confirm/index.js'

Vue.use(LoadingPlugin)
Vue.use(ConfirmPlugin)

import { List } from 'vant'
Vue.use(List)


Vue.config.productionTip = false
import Router from 'vue-router'
const routerPush = Router.prototype.push
Router.prototype.push = function push(location) {
return routerPush.call(this, location).catch(error=> error)
}
let echarts = require('echarts/lib/echarts');

require('echarts/lib/chart/line')
require('echarts/lib/chart/bar')
require('echarts/lib/chart/radar')

Vue.prototype.$echarts = echarts
/* eslint-disable no-new */







let instance = null
let routerInstance = null
function render (props = {}) {
const { container } = props
routerInstance = new VueRouter({
base: window.__POWERED_BY_QIANKUN__ ? "/safeRisk" : process.env.BASE_URL,
mode: 'history',
routes: router
})

instance = new Vue({
router: routerInstance,
store,
render: (h) => h(App)
}).$mount(container ? container.querySelector('#app') : '#app')
console.log(instance,"444")

}

if (!window.__POWERED_BY_QIANKUN__) {








render()
}else{
window.__webpack_public_path__ = window.__INJECTED_PUBLIC_PATH_BY_QIANKUN__; 

}

export async function bootstrap () {
console.log('[vue] vue app bootstraped')
}

export async function mount (props) {
console.log('[vue] props from main framework', props)

render(props)


}

export async function unmount () {
instance.$destroy()
instance.$el.innerHTML = ''
instance.$router.apps = []
instance = null
routerInstance = null
}







document.addEventListener("backbutton",lisUtils.exitApps, false)



