//截取url
function getUrl (url){
    let index = url.indexOf('/')
    let pre = url.substring(0,index + 1)
    let urls = url.substring(index + 1)
    let index1 = pre.indexOf('-')
    let urls1 = pre.substring(index1 + 1)
    return urls1 + urls //更改接口
    // return url //不更改接口
}
