//时间
export function getDate(date, type) {
    let d = new Date(date),
        month = '' + (d.getMonth() + 1),
        day = '' + d.getDate(),
        year = d.getFullYear(),
        hours = d.getHours() + '',
        minutes = d.getMinutes() + '',
        seconds = d.getSeconds() + '',
        millseconds = d.getMilliseconds() + '',
        timeStamp = d.getTime(), //时间戳
        echartsMonth = (d.getMonth() + 1) + '月'

    if (month.length < 2) month = '0' + month;
    if (day.length < 2) day = '0' + day;
    if (hours.length < 2) hours = '0' + hours;
    if (minutes.length < 2) minutes = '0' + minutes;
    if (seconds.length < 2) seconds = '0' + seconds;
    if (millseconds.length < 3) {
        if (millseconds.length < 2) {
            millseconds = '00' + millseconds
        } else {
            millseconds = '0' + millseconds
        }
    }

    //  return type == 'yy-mm-dd' ?  [year, month, day].join('-') : year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds;
    let times = ''
    if (type == 'yy-mm-dd') {
        times = [year, month, day].join('-')
    } else if (type == 'yy-mm') {
        times = [year, month].join('-')
    } else if (type == 'yy-mm-dd hh:mm:ss') {
        times = year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds;
    } else if (type == 'yy-mm-dd hh:mm:ss.ms') {
        times = year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds + '.' + millseconds;
    } else if (type == 'yyyy') {
        times = year
    } else if (type == 'mm') {
      times = echartsMonth
    } else if (type == 'm') {
      times = d.getMonth() + 1
    } else if (type == 'dd') {
        times = day
    }else if(type == 'hour'){
		times = hours
	}else if(type == 'minute'){
		times = minutes
	}else if(type == 'second'){
		times = seconds
	} else if (type == 'yy-mm-dd-china') {
        times = year + '年' + month + '月' + day + '日';
    } else {
        times = timeStamp
    }
    return times
}

export const findText = function (arr, value) {
  let target;
  if (value != undefined) {
    if (arr instanceof Array && arr.length) {
      for (let i = 0; i < arr.length; i++) {
        if (arr[i].value == value) {
          target = arr[i]
          break
        }
      }
      return target.text
    } else {
      return ''
    }
  } else {
    return ''
  }
}

export const findValue = function (arr, text) {
  let target;
  if (text != undefined) {
    if (arr instanceof Array && arr.length) {
      for (let i = 0; i < arr.length; i++) {
        if (arr[i].text == text) {
          target = arr[i]
          break
        }
      }
      return target.value
    } else {
      return ''
    }
  } else {
      return ''
  }
}

