import {
  guid,
  jsonSort,
  sm2Encrypt,
  sm2Decrypt
} from '@bj-nsc/functions'
const request = (type, params, url, Authorization, resolve, reject) => {
  console.log(url,Authorization,"111")
  TMFJSBridge.invoke('igwRequestV1', {
    type,
    appcode: 'HNINTJJQGCB',
    appservercode: 'base',
    areid: '1',
    params: {
      ...params,
      url,
      Authorization
    }
  }, function (res) {
    console.log("打印信息为：", res);
    if(res.errMsg === "ok") {
      resolve(res)
    }else{
      reject(res)
    }
  })
}
const axios = { 
  get: async (url, {
    params,
    headers
  }) => {
    console.log(url,"4444")
    let apiUrl = url
    if(apiUrl == '/api/comm/get_server_time') {
      apiUrl = apiUrl.replace("/api","")
    }
    const res = await sm2Encrypt(apiUrl)
    return new Promise(async (resolve, reject) => {
      console.log(params, res, headers.authorization)
      await request("GET", params, res, headers.authorization, resolve, reject)

    })
  },
  post: async (url, params, {
    headers
  }) => {
    const res = await sm2Encrypt(url)
    return new Promise(async (resolve, reject) => {
      await request("POST", params, res, headers.authorization, resolve, reject)
    })
  }
}
export default axios



