
import Tabbar from 'vux/src/components/tabbar/tabbar.vue'
import TabbarItem from 'vux/src/components/tabbar/tabbar-item.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'

import { mapGetters } from 'vuex'
export default {
components: {
Tabbar,
TabbarItem,
Group,
XInput,
LoadMore,
Scroller,
},
data() {
return {
list:[],
title : '消息',
src1:require('../assets/img/icon_msg1.png'),
src2:require('../assets/img/icon_ticket2.png'),
src3:require('../assets/img/icon_work1.png'),
src4:require('../assets/img/icon_mine1.png'),
token:'',
account: 'luol1213',//zhangpy1155/luol1213/liwy1213/
}
},
computed:{
...mapGetters({
msgNum: 'getMsgNum',
showTab: 'getShowTab'
})
},
created() {

},
mounted() {
},
watch: {



},
methods: {
changTab(value){
if (value == 0) {
this.title = '消息'
this.src1 = require('../assets/img/icon_msg2.png')
this.src2 = require('../assets/img/icon_ticket1.png')
this.src3 = require('../assets/img/icon_work1.png')
this.src4 = require('../assets/img/icon_mine1.png')
} else if (value==1) {
this.title='安全风险'
this.src1 = require('../assets/img/icon_msg1.png')
this.src2 = require('../assets/img/icon_ticket2.png')
this.src3 = require('../assets/img/icon_work1.png')
this.src4 = require('../assets/img/icon_mine1.png')
} else if (value==2) {
this.title='我的'
this.src1 = require('../assets/img/icon_msg1.png')
this.src2 = require('../assets/img/icon_ticket1.png')
this.src3 = require('../assets/img/icon_work1.png')
this.src4 = require('../assets/img/icon_mine2.png')
}
},
back() {
navigator.app.exitApp();
}
}
}



