import axios from 'axios';
import md5 from 'js-md5'
import {guid, jsonSort, sm2Encrypt, sm2Decrypt} from '@bj-nsc/functions'
import Session from '../../store/session'
//截取url
function getUrl (url){
  let index = url.indexOf('/api')
  let pre = url.substring(0,index + 1)
  let urls = url.substring(index)
  return urls //更改接口
  // return url //不更改接口
}
// axios 配置
// axios.defaults.timeout = 1 * 60 * 1000;
// axios.defaults.baseURL = '/api';
// http request 拦截器
axios.interceptors.request.use(
  config => {
    let token = Session.fetch('token')
    let datas = {}
    if(config.method == 'post'){
        datas = config.data
    }else{
        datas = config.params
    }
    const headerObj = {
    //   timestamp:
    //      Date.now() +
    //      (parseInt(Session.fetch('serverTime'), 10) || 0),
    //    onceStr: guid(),
       Authorization: token
    }
    let apiUrl = getUrl(config.url)
    if(apiUrl == '/api/comm/get_server_time'){
      let urls = config.url.replace('/api','')
      config.url = urls
      return config
    }
    datas.Authorization = token
    sm2Encrypt(apiUrl).then(res=>{
      datas.url = res
    })
    Object.assign(headerObj, { url: apiUrl }, datas)
    config.url = "/cdp/service/node/safe"
    let sortParam = jsonSort(headerObj,config.method)
    // let signature = md5(JSON.stringify(sortParam))
    // alert('headerObj:==>' + JSON.stringify(headerObj))
    // alert('signature:==>' + JSON.stringify(signature ))
    // config.headers.timestamp = headerObj.timestamp
    // config.headers.onceStr = headerObj.onceStr
    // config.headers.Authorization = token
    
    // alert(JSON.stringify(config))
    return config;
  },
  err => {
    // alert(JSON.stringify(err))
    return Promise.reject(err);
  }
);
export default axios;


