
import AlertModule from 'vux/src/plugins/alert/module'
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,getDate,commonDown } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import downPath from '../assets/js/getData'
import lisUtils from '../assets/js/units.js'
import { mapGetters } from 'vuex'
export default {
data (){
return {
unitData: [],//建管单位
projectData: [],//工程
programName: '',
unitId: [],
unitName: '',
projectName: '',
riskNumber: '',
projectId: [],
totals: 0,
tip: '暂无数据',
loading: false,
loading_s: true,
isGetMsg: false,
searchFlag: false,
showDialogStyle: false,
currentPage: 1,
pageSize: 5,
pageList: [],
showLoading: false,
routeItem: '',
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
show1: false,
text: '',
unitFlag: false,
proFlag: false,
sectionId: '',
platform: true,
typeData: [{name: '全部',value: ''},{name: '一般',value: '0'},{name: '专项',value: '1'}],
showMenus: false,
postId: '',
departFlag: false,
departData: [],
departId: [],
departName: '',
searchItem: '',
}
},
created (){
this.$store.commit('setShowTab',true)
if (device.platform != 'Android') this.platform = false
this.routeItem = this.$route.query.routeItem ? JSON.parse(this.$route.query.routeItem): ''
this.searchItem = this.$route.query.searchItem ? JSON.parse(this.$route.query.searchItem): ''
this.imitPage()
},
activated (){
if(this.sjfxAlive){
this.$store.commit('setShowTab',true)
}else{
this.$store.commit('setShowTab',true)
Object.assign(this.$data, this.$options.data())
if (device.platform != 'Android') this.platform = false
this.routeItem = this.$route.query.routeItem ? JSON.parse(this.$route.query.routeItem): ''
this.searchItem = this.$route.query.searchItem ? JSON.parse(this.$route.query.searchItem): ''
this.imitPage()
this.$store.commit('setSjfxAlive',true)
}
},
computed:{
...mapGetters({
sjfxAlive: 'getSjfxAlive',

})
},
mounted (){},
filters: {
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm
},
methods: {
toAdd (){
this.$router.push({path: '/addFengxianku'})
},
toGlfengxian (){
this.$router.push({path: '/glfengxianku'})
},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
showmore(){
this.showMenus = !this.showMenus;
this.showDialogStyle = !this.showDialogStyle;
},
imitPage (){






if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.workTicketLevel == 22) {
if(this.peopList.baseInfo.unitType == 'sgs'){
this.getOrg()
this.unitFlag = false
}else{
this.unitData = [{
name:this.searchItem.unitName,
value:this.searchItem.unitId.toString()
}]
this.unitId = [this.searchItem.unitId.toString()]
this.unitFlag = true
}
}else{
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 11){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
}else{
if(!this.peopList.project){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
}else{
this.postId = this.peopList.baseInfo.postcode
this.unitData = [{
name:this.peopList.project.unitName,
value:this.peopList.project.unitId.toString()
}]
this.unitId = [this.peopList.project.unitId.toString()]
this.unitFlag = true
}
}

}
if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.unitType == 'jg' || this.peopList.baseInfo.workTicketLevel == 22) {
if(this.peopList.baseInfo.workTicketLevel == 10){
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
this.departFlag = false
this.getDepart()
}else if(this.peopList.baseInfo.workTicketLevel == 21){
if(!this.peopList.project){
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
this.departFlag = false
this.getDepart()
}
}else{
if(this.peopList.baseInfo.unitType == 'sgs' || (this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 22)){
this.projectData = [{
name:this.searchItem.projectName,
value:this.searchItem.projectId.toString()
}]
this.projectId = [this.searchItem.projectId.toString()]
this.proFlag = true
this.departFlag = false
this.getDepart()
}else{
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}
}
}else{
if(!this.peopList.project){
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
if(this.peopList.departPermissionType == 'sg'){
if(!this.peopList.departPid){//施工项目部
this.departFlag = true
this.departData = [{
name: this.peopList.departName,
value:this.peopList.departId.toString()
}]
this.departId = [this.peopList.departId.toString()]
}else{
this.departFlag = true
this.departData = [{
name: this.peopList.departPName,
value:this.peopList.departPid.toString()
}]
this.departId = [this.peopList.departPid.toString()]
}
}else{
this.departFlag = false
this.getDepart()
}
}
}

this.query()

},

getOrg (){
let _this = this
let params = {

}
let urls = 'pms/api/v1/units/list/org/current-user'
commonGet(urls,params,function(res){
if(!res.status && res){
_this.unitData = res.map((item) => {
return {name: item.name,value: item.id.toString()}
})
if(_this.peopList.baseInfo.workTicketLevel == 22 && _this.unitData.length == 1){
_this.unitId = [res[0].id.toString()]
_this.getProjects()
}
if (_this.unitData.length == 1) {
_this.unitFlag = true
}
}
})
},
changeUnit (){
this.getProjects()
this.projectId = []
},

getProjects (){
let _this = this
let params = {

}
_this.projectData = []
let urls = 'pms/api/v1/unit_projects/list/unit/'+_this.unitId[0]
commonGet(urls,params,function(res){
if(!res.status && res){



_this.projectData = []
for(let i in res){
if(res[i].pid != '0'){
let item = {name: res[i].name,value: res[i].id.toString()}
_this.projectData.push(item)
}
}









}
})
},
changeProject (){
this.getDepart()
this.departId = []
},

getDepart (){
let _this = this
_this.departData = []
let params = {}
let urls = 'pms/api/v1/' + _this.projectId[0] + '/depart/sg'
commonGet(urls,params,function(res){
if(!res.status && res){




_this.departData = res.map((item) => {
return {
name: item.name,
value: item.id.toString()
}
})
}
})
},

showSkillPoint (id){
this.skillPointFlag = true
this.getSkillPointData(id)
},
getSkillPointData (id){
let _this = this
let params = {
programId: id
}
let urls = 'youotech-program/youotech/skillPoint'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.skillPointData = res.data
}
})
},

query (num){
if(num != 1){
this.searchFlag = false
this.showDialogStyle = false
}
this.currentPage = 1
this.getPageList()
},
cancel (){
this.searchFlag = !this.searchFlag
this.showDialogStyle = false
},

showSearch (){
this.searchFlag = !this.searchFlag
this.showDialogStyle = !this.showDialogStyle

},
onChangeUnit (val){
for(let i in this.unitData){
if(this.unitData[i].value == val){
this.unitName = this.unitData[i].name
}
}
},
onChangeProject (val){
for(let i in this.projectData){
if(this.projectData[i].value == val){
this.projectName = this.projectData[i].name
}
}
},
onChangeDepart (val){
for(let i in this.departData){
if(this.departData[i].value == val){
this.departName = this.departData[i].name
}
}
},
toDetail (id){
this.$router.push({path: '/addFengxianku',query: {id: id,isDetail: true}})
},

getPageList (){
let _this = this
_this.onChangeUnit(_this.unitId[0])
_this.onChangeProject(_this.projectId[0])
_this.onChangeDepart(_this.departId[0])
let params = {
current: _this.currentPage,
size: _this.pageSize,
projectId: _this.projectId[0],
buildUnitId: _this.unitId[0],
projectDeptCode: _this.departId[0],
sectionId: _this.sectionId,

riskNumber: _this.riskNumber
}
_this.showLoading = true
let urls = 'saferisk/risk/discern/inventory/item/pageList'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.totals = res.data.total
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.pageList = res.data.records
}else{
_this.pageList = _this.pageList.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.pageList = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
}
_this.loading = false
_this.showLoading = false
})
},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.getPageList()
_this.isGetMsg = false
}else{
return false
}
},
down (){
let _this = this;
this.showMenus = !this.showMenus;
this.showDialogStyle = !this.showDialogStyle;
if(_this.projectId.length == 0){
_this.show1 = true
_this.text = "请先选择工程"
}else{
_this.toDown()
}
},
toDown(){
let _this = this;
this.$vux.loading.show({
text: '加载中...'
})


if(_this.projectId.length>0){
_this.onChangeProject(_this.projectId[0])






}
var name= _this.projectName + "风险识别、评估清册_" + getDate(new Date(),'yy-mm-dd-china') + '.xls'
let params = {
projectId: _this.projectId[0],
projectName: _this.projectName,
sectionId: _this.sectionId
}
let urls = 'saferisk/risk/discern/inventory/export'
commonDown(urls,params,function(res){
let blob = new Blob([res], {
type: ''
})
let objectUrl = blob
lisUtils.createDir('', function(dirEntry) {
var configPath = dirEntry.fullPath + name
window.resolveLocalFileSystemURL(cordova.file.externalRootDirectory, function (root) {

root.getFile(configPath, {
create: true,
exclusive: false
},
function(fileEntry) {
fileEntry.file(function (file) {
var reader = new FileReader()
reader.onloadend = function() {

lisUtils.writeFile(fileEntry, objectUrl, false, configPath)
};
reader.readAsText(file);
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
})
})
















},
download(fileEntry, url) {
let _this = this;
var ft = new FileTransfer();
var fileURL = fileEntry.nativeURL;
ft.download(encodeURI(url), fileURL, function (entry) {
_this.$vux.loading.hide()


AlertModule.show({
title: '提示',
content: "下载成功!位置："+decodeURI(entry.nativeURL),
onHide () {
try {
var name = entry.name;
var ext = name.substr(name.lastIndexOf("."));
var type = 'application/vnd.android.package-archive';
if(ext == ".doc" || ext == ".docx" || ext == ".xls" || ext == ".xlsx") {
type = "application/msword";
} else if(ext == ".pdf") {
type = "application/pdf";
} else if(ext == ".gif") {
type = "application/gif";
} else if(ext == ".jpeg") {
type = "application/jpeg";
} else if(ext == ".png") {
type = "application/png";
} else if(ext == ".mpeg") {
type = "application/mpeg";
}else if(ext == '.zip'){
return false
}
var myFsRootDirectory1 = decodeURI(entry.nativeURL)
cordova.plugins.fileOpener2.open(myFsRootDirectory1, type, {
error: function(e) {


},
success: function() {
}
});
} catch(e) {

}
}
})
}, function (err) {
console.log(err)
_this.$vux.loading.hide()
_this.show1 = true
_this.text = "下载失败"
}, null,{
});
},
back (){
this.$router.go(-1)
}
}
}



