
import XTable from 'vux/src/components/x-table/index.vue'
import XTextarea from 'vux/src/components/x-textarea/index.vue'
import Checker from 'vux/src/components/checker/checker.vue'
import CheckerItem from 'vux/src/components/checker/checker-item.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,commonDelete,commonPost } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import { mapGetters } from 'vuex'
export default {
data (){
return {
pageList: [
],
showLoading: false,
peopList: Session.fetch('authorizationList'),
show1: false,
text: '',
showDialogStyle: false,

}
},
props: ['projectId','sectionId','partName'],
created (){
this.getPageList()
},
mounted (){},
filters: {
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
XTable,
},
methods: {
query (){
if(this.partName == ''){
for(let i in this.pageList){
this.pageList[i].isShow = true
}
return false
}
let item = []
item = this.pageList.filter(item =>
item.partName.indexOf(this.partName) !== -1
)
for(let i in this.pageList){
this.pageList[i].isShow = false
for(let j in item){
if(this.pageList[i].showIndex == item[j].showIndex){
this.pageList[i].isShow = true
}
}
}
},
getPageList (){
let _this = this
_this.showLoading = true
let params = {
projectId: _this.projectId,
sectionId: _this.sectionId,
beforeRisk: '2',
}
let urls = 'saferisk/risk/work/statistics/work/dgdw'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
res.data.forEach((item,index) => {
if(item.partName == null){
item.partName = ''
}
_this.$set(item,'isShow',true)
_this.$set(item,'showIndex',index)
})
_this.pageList = res.data
}else{
_this.text = res.other.msg
_this.show1 = true
}
})
},
back (){
this.$router.go(-1)

}
},
watch: {
}
}



