
import XInput from 'vux/src/components/x-input/index.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import Popup from 'vux/src/components/popup/index.vue'
import AlertModule from 'vux/src/plugins/alert/module'
import Datetime from 'vux/src/components/datetime/index.vue'
import Cell from 'vux/src/components/cell/index.vue'
import CellBox from 'vux/src/components/cell-box/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Loading from 'vux/src/components/loading/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import Store from '../store/store'
import Session from '../store/session'
import {commonGet, commonPosts,commonDown} from '../assets/js/getData'
import lisUtils from '../assets/js/units.js'
import { mapGetters } from 'vuex'
export default {
directives: {
TransferDom
},
components: {
XHeader,
Cell,
Group,
XDialog,
Confirm,
Loading,
Popup,
XButton,
CellBox,
XInput,
Datetime
},
data() {
return {
showContent001: false,
searchFlag: false,
showMenus: false,
showDialogStyle: false,
show: false,
showLoading: false,
platform: true,
list:[],
show1: false,
text: '',
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
routeItem: '',
home_list_top: 0,
home_list_left: 0,
searchValue: ''
}
},
created() {
this.$store.commit('setShowTab',true)

this.routeItem = this.$route.query.searchItem ? JSON.parse(this.$route.query.searchItem): ''
this.getSgsList()
},
activated (){
if(this.qcJgAlive){
this.$store.commit('setShowTab',true)
this.setPosition()
}else{
this.$store.commit('setShowTab',true)
Object.assign(this.$data, this.$options.data())

this.routeItem = this.$route.query.searchItem ? JSON.parse(this.$route.query.searchItem): ''
this.getSgsList()
this.$store.commit('setQcJgAlive',true)
}
},
computed:{
...mapGetters({

qcJgAlive: 'getQcJgAlive',
})
},
mounted() {
this.setPosition()
},
methods: {
setPosition (){
let attr = document.getElementById('menu_fx')
attr.scrollTop = this.home_list_top       
attr.scrollLeft = this.home_list_left       
attr.addEventListener("scroll",this.recordScrollPosition)
},
recordScrollPosition(e) {
this.home_list_top = e.target.scrollTop
this.home_list_left = e.target.scrollLeft
},
searchPart (){
let _this = this
if(_this.searchValue == ''){
for(let i in _this.list){
_this.list[i].isShow = true
}
return false
}
let item1 = []
item1 = _this.list.filter(item =>
item.projectName.indexOf(_this.searchValue) !== -1
)
let item2 = []
_this.list.forEach((item) => {
let item3 = []
item3 = item.childrenList.filter(i =>
i.projectName.indexOf(_this.searchValue) !== -1
)
if(item3.length>0){
item2.push(item)
}
})
item1 = item1.concat(item2)
for(let i in _this.list){
_this.list[i].isShow = false
for(let j in item1){
if(_this.list[i].projectId == item1[j].projectId){
_this.list[i].isShow = true
}
}
}
},
getSgsList (){
let _this = this
_this.showLoading = true
let params = {
type: 1,
unitId: _this.routeItem ? _this.routeItem.unitId: this.peopList.baseInfo.unitId,
}
let urls = 'saferisk/risk/discern/inventory/by/unit/project/tj'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.list = res.data.map((item) => {
return {
projectName: item.projectName,
projectId: item.projectId,
inventoryCount: item.inventoryCount,
childrenList: item.childrenList,
showChild: true,
isShow: true
}
})
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
toRiskBook (projectName,projectId){
this.$store.commit('setQcAlive',false)
let item = {
unitName: this.routeItem ? this.routeItem.unitName: this.peopList.baseInfo.unitName,
unitId: this.routeItem ? this.routeItem.unitId: this.peopList.baseInfo.unitId,
projectName: projectName,
projectId: projectId,
}
this.$router.push({path: '/fxshibie',query: {searchItem: JSON.stringify(item)}})
},
showmore(){
this.showMenus = !this.showMenus;
this.showDialogStyle = !this.showDialogStyle;
},

query (){
this.searchFlag = false
this.showDialogStyle = false
this.getSgsList()
},
cancel (){
this.searchFlag = false
this.showDialogStyle = false
},

showSearch (){
this.showMenus = false
this.searchFlag = !this.searchFlag
this.showDialogStyle = !this.showDialogStyle

},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
back() {
this.$router.go(-1)
},

downAll (){
let _this = this
this.showMenus = false
this.showDialogStyle = false
let params = {

}
let urls = 'youotech-saferisk/risk/ybz/export/name'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.downAllLoad(res.data)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
downAllLoad(name1){
let _this = this;
this.$vux.loading.show({
text: '加载中...'
})
var name=name1+".xls"
let params = {
}
let urls = 'saferisk/risk/ybz/export'
commonDown(urls,params,function(res){
let blob = new Blob([res], {
type: ''
})
let objectUrl = blob
lisUtils.createDir('', function(dirEntry) {
var configPath = dirEntry.fullPath + name
window.resolveLocalFileSystemURL(cordova.file.externalRootDirectory, function (root) {

root.getFile(configPath, {
create: true,
exclusive: false
},
function(fileEntry) {
fileEntry.file(function (file) {
var reader = new FileReader()
reader.onloadend = function() {

lisUtils.writeFile(fileEntry, objectUrl, false, configPath)
};
reader.readAsText(file);
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
})
})
},
download(fileEntry, url) {
let _this = this;
var ft = new FileTransfer();
var fileURL = fileEntry.nativeURL;
ft.download(encodeURI(url), fileURL, function (entry) {
_this.$vux.loading.hide()


AlertModule.show({
title: '提示',
content: "下载成功!位置："+decodeURI(entry.nativeURL),
onHide () {
try {
var name = entry.name;
var ext = name.substr(name.lastIndexOf("."));
var type = 'application/vnd.android.package-archive';
if(ext == ".doc" || ext == ".docx" || ext == ".xls" || ext == ".xlsx") {
type = "application/msword";
} else if(ext == ".pdf") {
type = "application/pdf";
} else if(ext == ".gif") {
type = "application/gif";
} else if(ext == ".jpeg") {
type = "application/jpeg";
} else if(ext == ".png") {
type = "application/png";
} else if(ext == ".mpeg") {
type = "application/mpeg";
}else if(ext == '.zip'){
return false
}
var myFsRootDirectory1 = decodeURI(entry.nativeURL)
cordova.plugins.fileOpener2.open(myFsRootDirectory1, type, {
error: function(e) {


},
success: function() {
}
});
} catch(e) {

}
}
})
}, function (err) {
console.log(err)
_this.$vux.loading.hide()
_this.show1 = true
_this.text = "下载失败"
}, null,{
});
},
},
watch: {
searchValue (newVal,oldVal){
this.searchPart()
}
}
}



