import { commonAjax, commonGet,commonDelete,commonPost } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import { mapGetters } from 'vuex'
import echarts from 'echarts'
export default {
data (){
return {
showDialogStyle: false,
showLoading: false,
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
show1: false,
text: '',
totals1:0,
totals2:0,
totals3:0,
arr:[],
arr1:[],
demo2: '',
ticketType: 0,
list2:[
{name: '各建管单位风险情况',value: '0'},
{name: '各建管单位风险明细',value: '1'},
],
list:[],
tabList:[],
pageList: [
{}
],
charts: '',
opinion:['男','女'],
opinionData:[
{value:335, name:'男'},
{value:310, name:'女'},

]

}
},
created (){
this.$store.commit('setShowTab',false)
this.getSgsList()

},
mounted() {
this.$nextTick(() => {
this.getEachat()
});
},
methods:{
getEachat(){
let _this = this
let params = {

}
let urls = 'saferisk/risk/analysis/detailList'
commonGet(urls,params,function(res){
console.log(res,"rssss")
if(res.code == 200){
_this.tabList = res.data
res.data.forEach(item => {
_this.arr.push({
value:item.riskNum,
name:item.shortName
})
_this.arr1.push(item.unitName)
})

let myChart = echarts.init(document.getElementById('main1'));

let option = {}
option = {
title : {
text: '各建管单位风险明细',//主标题

x:'center',//x轴方向对齐方式
},
tooltip : {
trigger: 'item',
formatter: "{b} : {c} ({d}%)"
},





series : [
{
name: '',
type: 'pie',
radius : '55%',
center: ['50%', '60%'],
data:_this.arr,//数据
itemStyle: {
emphasis: {
shadowBlur: 10,
shadowOffsetX: 0,
shadowColor: 'rgba(0, 0, 0, 0.5)'
}
}
}
]
};
myChart.setOption(option);
}else{
_this.show1 = true
_this.text = res.other.msg
}
})

},
onItemClick(){

},
back (){
this.$router.go(-1)

},
getSgsList (){
let _this = this

let params = {

}
let urls = 'saferisk/risk/analysis/unitList'
commonGet(urls,params,function(res){
console.log(res,"444444")
_this.showLoading = false
if(res.code == 200){
_this.totals1 = res.data.projectAllnum
_this.totals2 = res.data.riskAllNum
_this.totals3 = res.data.riskPartNum
_this.list = res.data.unitRiskList
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
toRiskBook (unitId,unitName){





this.$router.push({path: '/riskStatisticsDetail',query: {item: unitId}})
},
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
Tab,
TabItem,
Cell,
XTable,
},
}



