getPower (){
let _this = this
_this.showLoading = true
let params = {}
let urls = 'pms/api/v1/user-orgs'
commonGet(urls,params,function(res){
if (res.status || !res) {
_this.show1  = true
_this.text = '获取用户信息失败！'
_this.showLoading = false
return
}
_this.peopList = []
_this.unitType = res.unitType
if (res.participateUser == 1 && res.unitType != 'sgs') {
_this.getMesPower(res)
return
}
if(res.posts.length == 0 && res.unitType != 'sgs' && res.unitType !='jg'){
AlertModule.show({
title: '提示',
content: '无访问系统权限！',
onHide () {
_this.back()
}
})

_this.showLoading = false
return
}
let arrAll = _this.setPeopPower(res)
_this.showLoading = false
if (arrAll.length == 1 && res.unitType != 'yz') {
if(_this.messageId){
_this.getMessageDetail(arrAll)
}else{
Session.save('authorizationList',arrAll[0])
if(arrAll[0].baseInfo.unitType == 'sgs'){
_this.riskBookPath = '/riskBookSgs'
_this.riskStatisticsPath = '/riskStatistics'
_this.fxshibiePath = '/fxshibieSgs'
_this.sjfengxianPath = '/sjfengxianSgs'
_this.riskWorkPath = '/riskWorkSgs'
}else if(arrAll[0].baseInfo.unitType == 'jg' && arrAll[0].baseInfo.workTicketLevel == '22'){
_this.fxshibiePath = '/fxshibieJg'
_this.sjfengxianPath = '/sjfengxianJg'
_this.riskStatisticsPath = '/riskStatisticsDetail'
_this.riskWorkPath = '/riskWorkJg'
}
_this.peopType = arrAll[0].baseInfo.unitType
}
}else if(arrAll.length == 0){
_this.$vux.confirm.show({

title: '提示',
content: '未授权，请重新登陆',
showCancelButton: false,
onConfirm () {
_this.back()
}
})
}else{
if(_this.messageId){
_this.getMessageDetail(arrAll)
}else{
_this.peopList = arrAll
_this.show = true
}
}
Session.save('peopList',arrAll)
})
