getMessageDetail (peopArray){
let _this = this
_this.showLoading = true
let params = {}
let urls = 'msg/v1/' + _this.messageId
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
if(res.data.status == '5'){//1待办，5已处理
_this.$vux.confirm.show({

title: '提示',
content: '该消息已被处理！',
showCancelButton: false,
onConfirm () {
_this.back()
}
})
return
}
let ext = JSON.parse(res.data.ext)
let flag = false
let msgObj = {
taskId: ext.taskId,
peopMessageId: '',
operation: ext.operation,
operateType: ext.operateType
}
let powerObj = {}
peopArray.forEach(item => {
ext.messageRelatePeopList.forEach(item1 => {
if(ext.projectId == item.project.id && item.baseInfo.id == item1.peopId && item.baseInfo.postcode == item1.postId){
flag = true
msgObj.peopMessageId = item1.messageId
powerObj = item
}
})
})
if(!flag){
_this.$vux.confirm.show({

title: '提示',
content: '用户与消息权限不符，请重新登录！',
showCancelButton: false,
onConfirm () {
_this.back()
}
})
}else{
_this.selectPower(powerObj)
_this.readOne(msgObj)
}
}else{
_this.$vux.confirm.show({

title: '提示',
content: '获取消息详情失败！',
showCancelButton: false,
onConfirm () {
_this.back()
}
})
}
})
},

readOne (item){
let _this = this
_this.showLoading = true
let params = {
messageId: item.peopMessageId,
appMsgId: '1'
}
let urls = 'saferisk/message/read'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
item.readState = 1
if(item.operateType == '0'){//待办
if(item.operation){
_this.$router.push({path: '/'+ item.operation,query:{id: item.taskId}})
}
}else{
if(item.operation){
_this.$router.push({path: '/'+ item.operation,query:{id: item.taskId,isDetail: true}})
}
}
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
