searchProjectFun (){
this.peopList.forEach(item => {
item.baseInfo.isShow = false
})
if(this.searchProject == ''){
for(let i in this.peopList){
this.peopList[i].baseInfo.isShow = true
}
return false
}
let item = []
item = this.peopList.filter(item =>
item.project && Object.keys(item.project).length>0 && item.project.name.indexOf(this.searchProject) !== -1
)
for(let i in this.peopList){
this.peopList[i].baseInfo.isShow = false
for(let j in item){
if(this.peopList[i].id == item[j].id){
this.peopList[i].baseInfo.isShow = true
}
}
}

}
},
watch: {
searchProject (newVal,oldVal){
this.searchProjectFun()
}
}
