
import XTextarea from 'vux/src/components/x-textarea/index.vue'
import Checker from 'vux/src/components/checker/checker.vue'
import CheckerItem from 'vux/src/components/checker/checker-item.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,commonDelete,commonPost } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import downPath from '../assets/js/getData'
import { mapGetters } from 'vuex'
export default {
data (){
return {
totals: 0,
tip: '暂无数据',
loading: false,
loading_s: true,
isGetMsg: false,
searchFlag: false,
currentPage: 1,
pageSize: 5,
pageList: [],
showLoading: false,
peopList: Session.fetch('authorizationList'),
show1: false,
text: '',
showDialogStyle: false,
editFlag: false,
isChange: false
}
},
props: ['seachId','unitId','projectId','sectionId','departId','platform','canHandle','canReview','reportType'],
created (){
this.query()
},
mounted (){},
filters: {
setReportType (val){
if(val == '1'){
return '周计划'
}else if(val == '2'){
return '临时计划'
}
}
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
},
methods: {

peopPower (item){//true 为没权限
if(this.canReview){
if(item.nodeId == '55'){//1,2级风险编制
return true
}else if(item.nodeId == '56'){//1,2级风险施工项目经理审核
if(this.peopList.baseInfo.postcode == '4'){
return false
}else{
return true
}
}else if(item.nodeId == '57'){//1,2级风险审核通过
return true
}else if(item.nodeId == '67'){//3级风险编制
return true
}else if(item.nodeId == '68'){//3级风险监理审核
if(this.peopList.baseInfo.unitType == 'jl'){
return false
}else if(this.peopList.baseInfo.workTicketLevel == 21 && (this.peopList.baseInfo.postcode != '401' && this.peopList.baseInfo.postcode != '402')){
return false
}else{
return true
}
}else if(item.nodeId == '69'){//3级风险业主审核
if(this.peopList.baseInfo.workTicketLevel == 10){
return false
}else if(this.peopList.baseInfo.postcode == '401' || this.peopList.baseInfo.postcode == '402'){
return false
}else{
return true
}
}else if(item.nodeId == '70'){//3级风险审核通过
return true
}else if(item.nodeId == '80'){//4级风险编制
return true
}else if(item.nodeId == '81'){//4级风险监理审核
if(this.peopList.baseInfo.unitType == 'jl'){
return false
}else if(this.peopList.baseInfo.workTicketLevel == 21 && (this.peopList.baseInfo.postcode != '401' && this.peopList.baseInfo.postcode != '402')){
return false
}else{
return true
}
}else if(item.nodeId == '82'){//4级风险业主审核
if(this.peopList.baseInfo.postcode == '6' || this.peopList.baseInfo.postcode == '7'){
return false
}else if(this.peopList.baseInfo.postcode == '401' || this.peopList.baseInfo.postcode == '402'){
return false
}else{
return true
}
}else if(item.nodeId == '83'){//4级风险建管单位审核
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 22){
return false
}else{
return true
}






}else if(item.nodeId == '84'){//4级风险审核通过
return true
}else{
return true
}
}else{
return true
}
},

setEdit (item){//true 为没权限
if(this.canHandle){
if(item.nodeId == '55'){//1,2级风险编制
if(this.peopList.baseInfo.postcode == '3' || this.peopList.baseInfo.postcode == '12' || this.peopList.baseInfo.postcode == '4'){
return false
}else{
return true
}
}else if(item.nodeId == '67'){//3级风险编制
if(this.peopList.baseInfo.postcode == '12' || this.peopList.baseInfo.postcode == '4'){
return false
}else{
return true
}
}else if(item.nodeId == '80'){//4级风险编制
if(this.peopList.baseInfo.postcode == '12' || this.peopList.baseInfo.postcode == '4'){
return false
}else{
return true
}
}else{
return true
}
}else{
return true
}
},

rollback (item){
let _this = this
_this.showLoading = true
let params = {
id: item.id,
nodeId: item.nodeId,
taskState: '2',
taskPostId: _this.postId,
editRole:_this.peopList.baseInfo.postcode == '4'?'xmjl':'',
}
let urls = 'youotech-saferisk/risk/work/check'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.query()
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
toDetail (item){
this.$router.push({path: '/addRiskWork',query: {id: item.id,isDetail: true}})
},
toAdd (id,type){
this.$router.push({path: '/addRiskWork',query: {id: id,pageType: type}})
},
toAddRiskWork (){
this.$router.push({path: '/addRiskWork',query: {pageType: 'edit'}})
},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},

deleteMsg (id){
let _this = this
_this.showLoading = true
let params = {
}
let urls = 'youotech-saferisk/risk/work/delete?id='+id
commonDelete(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.query()
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

query (){
this.currentPage = 1
this.isChange = false
this.getPageList()
},

getPageList (){
let _this = this
if(_this.isChange){
return false
}
let params = {
current: _this.currentPage,
size: _this.pageSize,
projectId: _this.projectId[0],
buildUnitId: _this.unitId[0],
projectDeptCode: _this.departId[0],
sectionId: _this.sectionId,
riskLevel: _this.seachId,
state: '1',
reportType: _this.reportType
}
_this.showLoading = true
let urls = 'youotech-saferisk/risk/work/pageList'
commonGet(urls,params,function(res){
console.log(res,1111)
if(res.code == 200){
_this.totals = res.data.total
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.pageList = res.data.records
}else{
_this.pageList = _this.pageList.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.pageList = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom_rk1.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
}
_this.loading = false
_this.showLoading = false
})
},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
if(_this.isChange){
_this.isGetMsg = false
_this.query()
}else{
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.isGetMsg = false
_this.getPageList()
}
}else{
return false
}
},
back (){
this.$router.go(-1)

}
},
watch: {
unitId (newVal,oldVal){
this.isChange = true
},
projectId (newVal,oldVal){
this.isChange = true
},
seachId (newVal,oldVal){
this.isChange = true
},
departId (newVal,oldVal){
this.isChange = true
},
reportType (newVal,oldVal){
this.isChange = true
},
}
}



