
import XHeader from 'vux/src/components/x-header/index.vue'
import Datetime from 'vux/src/components/datetime/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,commonPost, getDate } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import downPath from '../assets/js/getData'
export default {
data (){
return {
projectTypeData: [],
projectTypeId: [''],
seachSpanList: [
{text: '全部',id: '',isChoose: true},
{text: '一级',id: '1',isChoose: false},
{text: '二级',id: '2',isChoose: false},
{text: '三级',id: '3',isChoose: false},
{text: '四级',id: '4',isChoose: false},
],
seachId: '',
unitData: [],//建管单位
projectData: [],//工程
programName: '',
unitId: [],
unitName: '',
projectName: '',
projectId: [],
totals: 0,
tip: '暂无数据',
loading: false,
loading_s: true,
isGetMsg: false,
searchFlag: false,
currentPage: 1,
pageSize: 5,
pageList: [],
showLoading: false,

peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
show1: false,
text: '',
unitFlag: false,
proFlag: false,
sectionId: '',
sectionName: '',
platform: true,
typeData: [{name: '全部',value: ''},{name: '一般',value: '0'},{name: '专项',value: '1'}],
showMenus: false,
showDialogStyle: false,
postId: '',
departName: '',
departId: '',
canSearchLevels: this.$route.query.levels,
reportType: this.$route.query.reportType,
workStartTime:'',
workEndTime:'',
workEndTime1:'',
editFlag:false,
startMinDate: '',//限制时间范围
startEndDate: '',//限制时间范围
endMinDate: '',//限制时间范围
}
},
created (){

this.$store.commit('setShowTab',false)
let today = new Date()
let week = today.getDay(); 
let minus = week ? week - 1 : 6;
today.setDate(today.getDate() - minus); 
let minDay = new Date(today)
minDay.setDate((today.getDate()+7))
let endDay = new Date(today)
endDay.setDate((today.getDate()+13))

if(this.reportType == '1'){
this.startMinDate = getDate(minDay,'yy-mm-dd')
this.startEndDate = getDate(endDay,'yy-mm-dd')
this.endMinDate = getDate(minDay,'yy-mm-dd')
}
this.imitPage()
},
mounted (){},
filters: {
},
directives: {
TransferDom
},
components: {
Datetime,
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm
},
methods: {

getProType (){
let _this = this
let params = {
branchPid: _this.peopList.project.type
}
let urls = 'youotech-saferisk/risk/library/dic/list'
commonGet(urls,params,function(res){
if(res.code == 200){
let list = res.data.map((item)=>{
return {name: item.projectTypeName,value: item.id.toString()}
})
_this.projectTypeData = list
let item = {name: '全部',value: ''}
_this.projectTypeData.unshift(item)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

clickSpan (id){
for(let i in this.seachSpanList){
if(id != this.seachSpanList[i].id){
this.seachSpanList[i].isChoose = false
}else{
this.seachSpanList[i].isChoose = true
this.seachId = this.seachSpanList[i].id
}
}
},
chooseItem (index){
this.pageList[index].isChoose = !this.pageList[index].isChoose







},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
showmore(){
this.showMenus = !this.showMenus;
this.showDialogStyle = !this.showDialogStyle
},
imitPage (){






if (this.peopList.baseInfo.unitType == 'sgs') {
this.getOrg()
this.unitFlag = false
}else{
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 11){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitName = this.peopList.baseInfo.unitName
this.unitFlag = true
}else{
this.postId = this.peopList.baseInfo.postId
this.unitData = [{
name:this.peopList.project.unitName,
value:this.peopList.project.unitId.toString()
}]
this.unitId = [this.peopList.project.unitId.toString()]
this.unitName = this.peopList.project.unitName
this.unitFlag = true
}

}



if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.unitType == 'jg' || this.peopList.baseInfo.workTicketLevel == 20) {
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.sectionName = this.peopList.sectionName
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
this.projectName = this.peopList.project.name
if(this.peopList.departPermissionType == 'sg'){
if(this.peopList.departPid){//存在pid则为班组
this.departId = this.peopList.departPid
this.departName = this.peopList.departPName
}else{//项目部
this.departId = this.peopList.departId
this.departName = this.peopList.departName
}
}
}



this.getProType()
this.getPageList()
},

getOrg (){
let _this = this
let params = {

}
let urls = 'pms/api/v1/units/list/org/current-user'
commonGet(urls,params,function(res){
if(!res.status && res){
_this.unitData = res.map((item) => {
return {name: item.name,value: item.id.toString()}
})



}
})
},
changeUnit (){
this.getProjects()
},

getProjects (){
let _this = this
let params = {

}
_this.projectData = []
let urls = 'pms/api/v1/unit_projects/list/unit/'+_this.unitId[0]
commonGet(urls,params,function(res){
if(!res.status && res){



for(let i in res){
if(res[i].pid != '0'){
let item = {name: res[i].name,value: res[i].id.toString()}
_this.projectData.push(item)
}
}



}
})
},
changetime (value) {
if(value) this.endMinDate = value
let today = new Date(value)
let endDay = new Date(today)
endDay.setDate((today.getDate()+29))
this.workEndTime1 = getDate(endDay,'yy-mm-dd')
},
changeEndDate (value){
if(value){
if(this.reportType == '2'){
this.startEndDate = value
}else{
let d = new Date(value)
let d1 = new Date(this.startEndDate)
let times = d.getTime() > d1.getTime() ? this.startEndDate: value
this.startEndDate = times
}
}
},

addRisk (){
let flag = false
for(let i in this.pageList){
if(this.pageList[i].isChoose){
flag = true
}
}
if(flag){
this.editFlag = true;

}else{
this.show1 = true
this.text = '请先选择风险'
}
},

saveRisk (){
let _this = this
_this.showLoading = true
let idList = []
for(let i in this.pageList){
if(this.pageList[i].isChoose){
idList.push(this.pageList[i].id)
}
}
let params = {
projectId: _this.projectId[0],
projectName: _this.projectName,
buildUnitId: _this.unitId[0],
buildUnitName: _this.unitName,
idList: idList,
sectionName: _this.sectionName,
sectionId: _this.sectionId,
projectType: _this.peopList.project.type,
projectDeptCode: _this.departId,
projectDeptName: _this.departName,
reportType: _this.reportType,
planStartTime: _this.workStartTime,
planEndTime: _this.workEndTime,
}
let urls = 'saferisk/risk/work/batch/inventory/save'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.$store.commit('setShowTab',true)
_this.$store.commit('setWorkAlive',false)
_this.$router.go(-1)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

query (){
this.searchFlag = false
this.showDialogStyle = false
this.currentPage = 1
this.getPageList()
},
cancel (){
this.searchFlag = false
this.showDialogStyle = false
},

showSearch (){
this.showMenus = false
this.searchFlag = !this.searchFlag
this.showDialogStyle = !this.showDialogStyle
},
onChangeUnit (val){
for(let i in this.unitData){
if(this.unitData[i].value == val){
this.unitName = this.unitData[i].name
}
}
},
onChangeProject (val){
for(let i in this.projectData){
if(this.projectData[i].value == val){
this.projectName = this.projectData[i].name
}
}
},

getPageList (){
let _this = this
let params = {
current: _this.currentPage,
size: _this.pageSize,
levels: _this.canSearchLevels,
projectTypeId: _this.projectTypeId.length>0 ? _this.projectTypeId[0]: '',
projectId: _this.projectId.length>0 ? _this.projectId[0]: '',
sectionId: _this.sectionId,
}
_this.showLoading = true
let urls = 'saferisk/risk/discern/inventory/gl/pageList'
commonGet(urls,params,function(res){
if(res.code == 200){
for(let i in res.data.records){
let item = {riskPreControlMeasure: '',isChoose: false}
for(let j in res.data.records[i].riskPreControlMeasureListVo){
item.riskPreControlMeasure = item.riskPreControlMeasure + ',' + res.data.records[i].riskPreControlMeasureListVo[j].content
}
item.riskPreControlMeasure = item.riskPreControlMeasure.substr(1)
res.data.records[i] = Object.assign(res.data.records[i],item)
console.log(res.data.records[i])
}
_this.totals = res.data.total
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.pageList = res.data.records
}else{
_this.pageList = _this.pageList.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.pageList = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom1.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
}
_this.loading = false
_this.showLoading = false
})
},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.isGetMsg = false
_this.getPageList()
}else{
return false
}
},
back (){
this.$store.commit('setShowTab',true)
this.$store.commit('setWorkAlive',false)
this.$router.go(-1)
}
}
}



