cancelQcItem (){
if(this.isAllPart){
let newList = this.qcListNew.concat(this.qcList)
this.qcList = newList.concat([])
this.isAllPart = false
this.showEditQc = false
}else{
this.showEditQc = false
}
},
saveQcItem (){
if(this.isAllPart){
let patt =  /^[\s]*$/
for(let i=0;i<this.qcForm.riskDiscernInventoryPartList.lelgth;i++){
if(this.qcForm.riskDiscernInventoryPartList[i].partName == '' || patt.test(this.qcForm.riskDiscernInventoryPartList[i].partName)){
this.qcForm.riskDiscernInventoryPartList.splice(i,1)
i--
}
}
this.qcForm.riskDiscernInventoryPartList.forEach(item => {
if(item.partId == '' || item.partId == null){
this.qcForm.extendWorkPart = this.qcForm.extendWorkPart + ',' + item.partName
}
})
this.qcForm.extendWorkPart = this.qcForm.extendWorkPart.substr(1)
this.qcListNew.forEach(item => {
item.workPart = this.qcForm.workPart
item.extendWorkPart = this.qcForm.extendWorkPart
item.latitude = this.qcForm.latitude
item.longitude = this.qcForm.longitude
item.ll = this.qcForm.ll
item.siteDetail = this.qcForm.siteDetail
item.riskDiscernInventoryPartList = this.qcForm.riskDiscernInventoryPartList
item.partIds = this.partId.join(',')
if(this.qcForm.workPart && this.qcForm.extendWorkPart){
item.hbWorkPart = this.qcForm.workPart + ',' + this.qcForm.extendWorkPart
}else{
if(this.qcForm.workPart){
item.hbWorkPart = this.qcForm.workPart
}else if(this.qcForm.extendWorkPart){
item.hbWorkPart = this.qcForm.extendWorkPart
}
}
})
this.isAllPart = false
this.showEditQc = false
let newList = this.qcListNew.concat(this.qcList)
this.qcList = newList.concat([])
}else{
if(this.qcForm.riskDiscernInventoryPartList.length==0 || !this.qcForm.workContent){
this.text = '请正确填写每一项'
this.show1 = true
}else{
this.toSaveQcItem()
}
}
},
toSaveQcItem (){
