executeType: type,
projectId: Session.fetch('authorizationList').project ? Session.fetch('authorizationList').project.id: '',
appMsgId: '1',
postId: _this.peopList.baseInfo.postcode ? _this.peopList.baseInfo.postcode: ''
}
let urls = 'youotech-saferisk/message/batch/read'
commonPost(urls,params,function(res){
_this.showLoading = false


if(res.code == 200){







_this.query()
_this.$store.commit('setMsgNum',0)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
query (){
this.currentPage = 1
this.getMsgList()
},

getMsgList (){
let _this = this
_this.showLoading = true
let params = {
operateType: _this.operateType,
current: _this.currentPage,
size: _this.pageSize,
projectId: Session.fetch('authorizationList').project ? Session.fetch('authorizationList').project.id: '',
appMsgId: '1',
postId: _this.peopList.baseInfo.postcode ? _this.peopList.baseInfo.postcode: ''
}
let urls = 'youotech-saferisk/message/pageList'
commonGet(urls,params,function(res){
if(res.code == 200){
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.list = res.data.records
}else{
_this.list = _this.list.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.list = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
_this.show1 = true
_this.text = res.other.msg
}
_this.loading = false
_this.showLoading = false
let msgNum = 0
for(let i in _this.list){
if(_this.list[i].readState == 0){
msgNum++
}
}
_this.$store.commit('setMsgNum',msgNum)
})
},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.getMsgList()
_this.isGetMsg = false
}else{
return false
}
},
onConfirm (){},
subOk (index){
if(this.$refs.scrollerBottom && this.$refs.scrollerBottom.reset) this.$refs.scrollerBottom.reset({top: 0});
this.operateType = index
this.currentPage=1;
this.list=[];
this.onFetching = false;
this.loading =false;
this.getMsgList();
},
back (){
navigator.app.exitApp();
}
}
