}
},
created() {

this.getSgsList()
},
mounted() {
},
methods: {
getSgsList (){
let _this = this
_this.showLoading = true
let params = {
ticketId: _this.ticketId
}
let urls = 'saferisk/risk/work/dgdw/list'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
for(let i in res.data){
if(res.data[i].count>0){
res.data[i].stateCount = '已履职/' + res.data[i].count + '次'
}else{
res.data[i].stateCount = '未履职'
}
}
_this.list = res.data
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
toStation (item){
if(item.count > 0){
this.$router.push({path: '/workManage_station',query: {unitItem: item,ticketId: this.ticketId}})
}
},
toRiskBook (unitName,unitId){
let item = {
unitName: unitName,
unitId: unitId,
time: this.searchTime
}
this.$router.push({path: '/riskBook',query: {searchItem: JSON.stringify(item)}})
},
showmore(){
this.showMenus = !this.showMenus;
this.showDialogStyle = !this.showDialogStyle;
},

query (){
this.searchFlag = false
this.showDialogStyle = false
this.getSgsList()
},
cancel (){
this.searchFlag = false
this.showDialogStyle = false
},

showSearch (){
this.showMenus = false
this.searchFlag = !this.searchFlag
this.showDialogStyle = !this.showDialogStyle

},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
back() {
this.$router.go(-1)
},

downAll (){
let _this = this
this.showMenus = false
this.showDialogStyle = false
let params = {

}
let urls = 'youotech-saferisk/risk/ybz/export/name'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.downAllLoad(res.data)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
downAllLoad(name1){
let _this = this;
this.$vux.loading.show({
text: '加载中...'
})
var name=name1+".xls"
window.resolveLocalFileSystemURL(cordova.file.externalRootDirectory, function (root) {


let url = downPath + 'youotech-saferisk/risk/ybz/export?&authorization=' + _this.token
root.getFile(name, { create: true }, function (fileEntry) {
_this.download(fileEntry, url);
},function(error){
_this.show1 = true
_this.text = "下载失败"
_this.$vux.loading.hide()
});
},function(error){
_this.show1 = true
_this.text = "下载失败"
_this.$vux.loading.hide()
})
},
download(fileEntry, url) {
let _this = this;
var ft = new FileTransfer();
var fileURL = fileEntry.nativeURL;
ft.download(encodeURI(url), fileURL, function (entry) {
_this.$vux.loading.hide()


AlertModule.show({
title: '提示',
content: "下载成功!位置："+decodeURI(entry.nativeURL),
onHide () {
try {
var name = entry.name;
var ext = name.substr(name.lastIndexOf("."));
var type = 'application/vnd.android.package-archive';
if(ext == ".doc" || ext == ".docx" || ext == ".xls" || ext == ".xlsx") {
type = "application/msword";
} else if(ext == ".pdf") {
type = "application/pdf";
} else if(ext == ".gif") {
type = "application/gif";
} else if(ext == ".jpeg") {
type = "application/jpeg";
} else if(ext == ".png") {
type = "application/png";
} else if(ext == ".mpeg") {
type = "application/mpeg";
}else if(ext == '.zip'){
return false
}
var myFsRootDirectory1 = decodeURI(entry.nativeURL)
cordova.plugins.fileOpener2.open(myFsRootDirectory1, type, {
error: function(e) {


},
success: function() {
}
});
} catch(e) {

}
}
})
}, function (err) {
console.log(err)
_this.$vux.loading.hide()
_this.show1 = true
_this.text = "下载失败"
}, null,{
});
},
},
}



