}
}
},
toLookFile (item,type){
let _this = this
this.imgList = []
if(type == '1'){
_this.showLoading = true
let params = {
id: item.riskTzfkdNoticeVo.id,
type: '2'
}
let urls = 'saferisk//risk/tzfkd/notice/download'
commonDown1(urls,params,function(res){
_this.showLoading = false
let blob = new Blob([res.data], {
type: ''
})
let objectUrl = URL.createObjectURL(blob)
let contentDisposition = res.headers['filename'];
let fileName = decodeURI(contentDisposition)
let index = fileName.lastIndexOf(".");
let hzm = fileName.substring(index+1);
if(hzm == 'pdf' || hzm == 'PDF'){
_this.filePath = 'static/pdf/web/viewer.html?file=' + objectUrl
_this.showFile = true
}else{
_this.imgPath = objectUrl
let data = {
msrc: _this.imgPath,
src: _this.imgPath
}
_this.imgList.push(data)
_this.imgFlag = true
}
})
}else{
_this.showLoading = true
let params = {
id: item.id,
type: '2'
}
let urls = 'saferisk//risk/tzfkd/feedback/download'
commonDown1(urls,params,function(res){
_this.showLoading = false
let blob = new Blob([res.data], {
type: ''
})
let objectUrl = URL.createObjectURL(blob)
let contentDisposition = res.headers['filename'];
let fileName = decodeURI(contentDisposition)
let index = fileName.lastIndexOf(".");
let hzm = fileName.substring(index+1);
if(hzm == 'pdf' || hzm == 'PDF'){
_this.filePath = 'static/pdf/web/viewer.html?file=' + objectUrl
_this.showFile = true
}else{
_this.imgPath = objectUrl
let data = {
msrc: _this.imgPath,
src: _this.imgPath
}
_this.imgList.push(data)
_this.imgFlag = true
}
})
}
},
closePreview (){
