this.showDialogStyle = !this.showDialogStyle;
},

setNoticePower (data,type){//type: 新增add 、编辑edit 、预览preview 、下载download 、上传upload 、记录write 、查看look 、审核check 、发布release 、解除remove 、作废invalid

if(data.riskTzfkdNoticeVo){
if(type == 'add'){
return false
}else if(type == 'edit'){
if(data.riskTzfkdNoticeVo.nodeId == '101' || data.riskTzfkdNoticeVo.nodeId == '113' || data.riskTzfkdNoticeVo.nodeId == '106' || data.riskTzfkdNoticeVo.nodeId == '119'){//待提交/作废
if(this.canHandle){
return true
}else{
return false
}
}else{
return false
}
}else if(type == 'preview' || type == 'download' || type == 'write'){
if(data.riskTzfkdNoticeVo.nodeId != '101' && data.riskTzfkdNoticeVo.nodeId != '113'){
return true
}else{
return false
}
}else if(type == 'upload' || type == 'release'){
if(data.riskTzfkdNoticeVo.nodeId == '103' || data.riskTzfkdNoticeVo.nodeId == '116'){//待发布
if(this.canHandle){
return true
}else{
return false
}
}else{
return false
}


}else if(type == 'look'){
if(data.riskTzfkdNoticeVo.nodeId != '101' && data.riskTzfkdNoticeVo.nodeId != '113' && data.riskTzfkdNoticeVo.nodeId != '106' && data.riskTzfkdNoticeVo.nodeId != '119'){
return true
}else{
return false
}
}else if(type == 'check'){
if(data.riskTzfkdNoticeVo.nodeId == '102' || data.riskTzfkdNoticeVo.nodeId == '114'){
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 22){
return true
}else{
return false
}
}else if(data.riskTzfkdNoticeVo.nodeId == '115'){
if(this.peopList.baseInfo.unitType == 'sgs'){
return true
}else{
return false
}
}else{
return false
}
}else if(type == 'remove'){
if(data.riskTzfkdNoticeVo.nodeId == '104' || data.riskTzfkdNoticeVo.nodeId == '117'){//已发布
if(this.canHandle){
return true
}else{
return false
}
}else{
return false
}
}else if(type == 'invalid'){
if(data.riskTzfkdNoticeVo.nodeId == '104' || data.riskTzfkdNoticeVo.nodeId == '117' || data.riskTzfkdNoticeVo.nodeId == '105' || data.riskTzfkdNoticeVo.nodeId == '118'){//已发布、已解除
if(this.canHandle){
return true
}else{
return false
}
}else{
return false
}
}else{
return false
}
}else{
if(type == 'add'){
if(this.canHandle){
return true
}else{
return false
}
}else{
return false
}
}
},
imitPage (){
if(this.peopList.baseInfo.unitType == 'sgs'){
this.canHandle = false
this.canReview = true
}else if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 22){
this.canHandle = true
this.canReview = true
}else{
this.canHandle = false
this.canReview = false
}
if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.workTicketLevel == 22) {
this.getOrg()
this.unitFlag = false
}else{
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 11){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
}else{
if(!this.peopList.project){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
}else{
this.postId = this.peopList.baseInfo.postcode
this.unitData = [{
name:this.peopList.project.unitName,
value:this.peopList.project.unitId.toString()
}]
this.unitId = [this.peopList.project.unitId.toString()]
this.unitFlag = true
}
}

}
if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.unitType == 'jg' || this.peopList.baseInfo.workTicketLevel == 22) {
if(this.peopList.baseInfo.workTicketLevel == 10){
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
}else if(this.peopList.baseInfo.workTicketLevel == 21){
if(!this.peopList.project){
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
}
}else{
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}
}else{
if(!this.peopList.project){
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
}
}

this.query()

},

getOrg (){
let _this = this
let params = {

}
let urls = 'pms/api/v1/units/list/org/current-user'
commonGet(urls,params,function(res){
if(!res.status && res){
_this.unitData = res.map((item) => {
return {name: item.name,value: item.id.toString()}
})
if(_this.routeItem){
_this.unitId = [_this.routeItem.buildUnitId.toString()]
}
}
})
},
changeUnit (){
this.projectId = []
this.getProjects()
},

getProjects (){
let _this = this
let params = {

}
_this.projectData = []
let urls = 'pms/api/v1/unit_projects/list/unit/'+_this.unitId[0]
commonGet(urls,params,function(res){
if(!res.status && res){



for(let i in res){
if(res[i].pid != '0'){
let item = {name: res[i].name,value: res[i].id.toString()}
_this.projectData.push(item)
}
}
if(_this.routeItem){
_this.projectId = [_this.routeItem.projectId.toString()]
}
}
})
},

query (){
this.searchFlag = false
this.showDialogStyle = false
this.currentPage = 1
this.getPageList()
},
cancel (){
this.searchFlag = false
this.showDialogStyle = false
},

showSearch (){
this.searchFlag = !this.searchFlag
this.showDialogStyle = !this.showDialogStyle

},
onChangeUnit (val){
for(let i in this.unitData){
if(this.unitData[i].value == val){
this.unitName = this.unitData[i].name
}
}
},
onChangeProject (val){
for(let i in this.projectData){
if(this.projectData[i].value == val){
this.projectName = this.projectData[i].name
}
}
},

getPageList (){
let _this = this
_this.onChangeUnit(_this.unitId[0])
_this.onChangeProject(_this.projectId[0])
let params = {
current: _this.currentPage,
size: _this.pageSize,
state: _this.state.length>0 ? _this.state[0]: '',
buildUnitId: _this.unitId.length>0 ? _this.unitId[0]: '',
projectId: _this.projectId.length>0 ? _this.projectId[0]: '',
riskLevel: _this.seachId,
releaseDate: _this.checkDate,
appType: '2'
}
_this.showLoading = true
let urls = 'saferisk/risk/tzfkd/pageList'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.totals = res.data.total
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.pageList = res.data.records
}else{
_this.pageList = _this.pageList.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.pageList = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
}
_this.loading = false
_this.showLoading = false
})
},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.getPageList()
_this.isGetMsg = false
}else{
return false
}
},
toDown(item){
let _this = this;
this.$vux.loading.show({
text: '加载中...'
})
let params = {
id: item.id
}
let urls = 'saferisk/risk/tzfkd/download'
commonDown1(urls,params,function(res){
let blob = new Blob([res.data], {
type: ''
})
let objectUrl = blob
let contentDisposition = res.headers['filename'];
let fileName = decodeURI(contentDisposition)
lisUtils.createDir('', function(dirEntry) {
var configPath = dirEntry.fullPath + fileName
window.resolveLocalFileSystemURL(cordova.file.externalRootDirectory, function (root) {

root.getFile(configPath, {
create: true,
exclusive: false
},
function(fileEntry) {
fileEntry.file(function (file) {
var reader = new FileReader()
reader.onloadend = function() {

lisUtils.writeFile(fileEntry, objectUrl, false, configPath)
};
reader.readAsText(file);
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
})
})
},
download(fileEntry, url) {
let _this = this;
var ft = new FileTransfer();
var fileURL = fileEntry.nativeURL;
ft.download(encodeURI(url), fileURL, function (entry) {
_this.$vux.loading.hide()


AlertModule.show({
title: '提示',
content: "下载成功!位置："+decodeURI(entry.nativeURL),
onHide () {
try {
var name = entry.name;
var ext = name.substr(name.lastIndexOf("."));
var type = 'application/vnd.android.package-archive';
if(ext == ".doc" || ext == ".docx" || ext == ".xls" || ext == ".xlsx") {
type = "application/msword";
} else if(ext == ".pdf") {
type = "application/pdf";
} else if(ext == ".gif") {
type = "application/gif";
} else if(ext == ".jpeg") {
type = "application/jpeg";
} else if(ext == ".png") {
type = "application/png";
} else if(ext == ".mpeg") {
type = "application/mpeg";
}else if(ext == '.zip'){
return false
}
var myFsRootDirectory1 = decodeURI(entry.nativeURL)
cordova.plugins.fileOpener2.open(myFsRootDirectory1, type, {
error: function(e) {


},
success: function() {
}
});
} catch(e) {

}
}
})
}, function (err) {
console.log(err)
_this.$vux.loading.hide()
_this.show1 = true
_this.text = "下载失败"
}, null,{
});
},
back (){
this.$router.go(-1)
}
}
}



