
import Tab from 'vux/src/components/tab/tab.vue'
import TabItem from 'vux/src/components/tab/tab-item.vue'
import XTextarea from 'vux/src/components/x-textarea/index.vue'
import Checker from 'vux/src/components/checker/checker.vue'
import CheckerItem from 'vux/src/components/checker/checker-item.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,commonDelete,commonPost } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import { mapGetters } from 'vuex'
export default {
data (){
return {
showDialogStyle: false,
totals: 0,
tip: '暂无数据',
loading: false,
loading_s: true,
isGetMsg: false,
currentPage: 1,
pageSize: 5,
pageList: [{},{},{}],
showLoading: false,
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
show1: false,
text: '',
unitId: '',
projectId: '',
sectionId: '',
level: '',
type: '',

}
},
created (){
this.$store.commit('setShowTab',true)
this.unitId = this.$route.query.unitId
this.projectId = this.$route.query.projectId
this.sectionId = this.$route.query.sectionId
this.level = this.$route.query.level
this.type = this.$route.query.type
this.query()
},
activated (){
if(this.riskTicketListAlive){
this.$store.commit('setShowTab',true)
}else{
this.$store.commit('setShowTab',true)
Object.assign(this.$data, this.$options.data())
this.$store.commit('setRiskTicketListAlive',true)
this.unitId = this.$route.query.unitId
this.projectId = this.$route.query.projectId
this.sectionId = this.$route.query.sectionId
this.level = this.$route.query.level
this.type = this.$route.query.type
this.query()
}
},
computed:{
...mapGetters({
riskTicketListAlive: 'getRiskTicketListAlive',
})
},
mounted (){},
filters: {
stateVal (num) { //作业票当前状态
switch(num) {
case 1:
case '1':
return '编制';
case 2:
case '2':
return '待审核';
case 3:
case '3':
return '待签发';
case 4:
case '4':
return '监理待签字';
case 5:
case '5':
return '业主待签字';
case 6:
case '6':
return '待申请终结';
case 7:
case '7':
return '待终结';
case 8:
case '8':
return '已终结';
case 9:
case '9':
return '已作废';
case 10:
case '10':
return '待审核';
case 11:
case '11':
return '待审核';
case 12:
case '12':
return '监理待签字';
case 13:
case '13':
return '已过期';
default:
;
break;
}
},
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
Tab,
TabItem,
},
methods: {
toTicketDetail (ticketId){
this.$router.push({path: '/workManage_ticketDetail',query:{ticketId: ticketId}})
},
query(){
this.currentPage = 1
this.getPageList()
},


getPageList (){
let _this = this
if(_this.isChange){
return false
}
let params = {
current: _this.currentPage,
size: _this.pageSize,
projectId: _this.projectId,
buildUnitId: _this.unitI,
sectionId: _this.sectionId,
afterRisk: _this.level,
workTicketState: _this.type
}
_this.showLoading = true
let urls = 'saferisk/risk/work/statistics/work/ticket/pageList'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.totals = res.data.total
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.pageList = res.data.records
}else{
_this.pageList = _this.pageList.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.pageList = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom_rk1.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
}
_this.loading = false
_this.showLoading = false
})
},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.isGetMsg = false
_this.getPageList()
}else{
return false
}
},



back (){
this.$router.go(-1)

}
},
watch: {
}
}



