
import Checker from 'vux/src/components/checker/checker.vue'
import Search from 'vux/src/components/search/index.vue'
import Cell from 'vux/src/components/cell/index.vue'
import Checklist from 'vux/src/components/checklist/index.vue'
import CheckerItem from 'vux/src/components/checker/checker-item.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import XTextarea from 'vux/src/components/x-textarea/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,commonPost } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import downPath from '../assets/js/getData'

export default {
data (){
return {
noticeDetail:{},
mind: '',
showLoading: false,
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
show1: false,
text: '',
commonList: [
{key: '1',value: '是',ckecked:true,},
{key: '2',value: '否'},
],
radioValue: '1',
id: this.$route.query.id,
isDetail: this.$route.query.isDetail,
pageType: this.$route.query.pageType,
canReview: false,
}
},
created (){
this.$store.commit('setShowTab',false)
this.initPage()
},
mounted (){},
filters: {
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
Checklist,
Cell,
Search
},
methods: {
autoSize (){
this.$nextTick(function(){
this.$refs.demoObject.updateAutosize()
this.$refs.demoObject1.updateAutosize()
})
},

onItemClick (value, disabled) {
let _this = this
this.commonList.forEach(e=>{
if(e.key == value){
_this.$set(e,'ckecked',true)
e.ckecked = true
}else{
this.$set(e,'ckecked',false)
e.ckecked = false
}
})
this.radioValue = value.toString()
},
setPower (nodeId){
},
initPage (){
if(this.peopList.baseInfo.unitType == 'sgs'){
this.canReview = true
}else if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 22){
this.canReview = true
}else{
this.canReview = false
}
if(this.isDetail){
this.canReview = false
}
this.getDetail()
},

submitMsg (){
let _this = this
_this.showLoading = true
let params = {
id: _this.id,
nodeId: _this.noticeDetail.nodeId,
taskState: _this.radioValue,
idea: _this.mind
}
let urls = 'saferisk/risk/tzfkd/notice/check'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.$store.commit('setNoticeAlive',false)
_this.$store.commit('setShowTab',true)
_this.$router.go(-1)
}else{
_this.text = res.other.msg
_this.show1 = true
}
})
},

getDetail (){
let _this = this
_this.showLoading = true
let params = {
id: _this.id
}
let urls = 'saferisk/risk/tzfkd/notice/detail'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.noticeDetail = res.data
}else{
_this.text = res.other.msg
_this.show1 = true
}
})
},

changeRadio (val, label){
console.log('change:', val, label)
},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
back (){
let _this = this
if(_this.pageType == 'edit'){
_this.$vux.confirm.show({

title: '提示',
content: '当前风险通知单尚未审核，确定返回？',
onCancel () {
},
onConfirm () {
_this.$store.commit('setShowTab',true)
_this.$router.go(-1)
}
})
}else{
_this.$store.commit('setShowTab',true)
_this.$router.go(-1)
}

}
},
}



