import Vue from 'vue'
import AlertModule from 'vux/src/plugins/alert/module'

import router from '@/router'


let lisUtils = {
exitApps: function() {
let strUrl=window.location.href
var arrUrl=strUrl.split("/");
var strPage=arrUrl[arrUrl.length-1];
if (strPage == 'menu' || strPage == 'mine' || strPage == 'Menu' || strPage == 'Mine' || strPage == 'msg' || strPage == 'Msg') {
navigator.app.exitApp();
}else{
if(strPage == 'fxshibie' || strPage == 'Fxshibie'){

}else{
router.go(-1);
}
}
},

dataURLtoFile: function(dataurl, filename) {
var arr = dataurl.split(','),
mime = arr[0].match(/:(.*?);/)[1],
bstr = atob(arr[1]),
n = bstr.length,
u8arr = new Uint8Array(n);
while (n--) {
u8arr[n] = bstr.charCodeAt(n);
}
return new File([u8arr], filename, { type: mime });
},
dataURLtoFiles(urlData, fileName) {
var bytes = window.atob(urlData.split(',')[1]);        
var mime = urlData.split(',')[0].match(/:(.*?);/)[1];

var ab = new ArrayBuffer(bytes.length);
var ia = new Uint8Array(ab);
for (var i = 0; i < bytes.length; i++) {
ia[i] = bytes.charCodeAt(i);
}
return new File([ab], fileName, { type: mime });
},

dataURLtoBlob: function(dataurl) {
var arr = dataurl.split(','),
mime = arr[0].match(/:(.*?);/)[1],
bstr = atob(arr[1]),
n = bstr.length,
u8arr = new Uint8Array(n);
while (n--) {
u8arr[n] = bstr.charCodeAt(n);
}
return new Blob([u8arr], { type: mime });
},

blobToFile: function(theBlob, fileName){
theBlob.lastModifiedDate = new Date();
theBlob.name = fileName;
theBlob.filename = fileName;
return theBlob;
},
createDir: function(dir,callback){
window.requestFileSystem = window.requestFileSystem || window.webkitRequestFileSystem;
window.requestFileSystem(window.PERSISTENT, 5 * 1024, initFs, errorHandler);
function initFs(fs) {

fs.root.getDirectory( dir, { create: true }, function (dirEntry) {
try{
callback(dirEntry);
}catch(e){
console.log(e.message);
}

}, errorHandler);
}

function errorHandler(err) {
console.log(err);
}
},
writeFile: function(fileEntry, dataObj, isAppend, configPath) {

fileEntry.createWriter(function (fileWriter) {

fileWriter.onwriteend = function() {
Vue.$vux.loading.hide()
AlertModule.show({
title: '提示',
content: "下载成功!位置："+decodeURI(fileEntry.nativeURL),
onHide () {
try {
var name = fileEntry.name;
var ext = name.substr(name.lastIndexOf("."));
var type = 'application/vnd.android.package-archive';
if(ext == ".doc" || ext == ".docx" || ext == ".xls" || ext == ".xlsx") {
type = "application/msword";
} else if(ext == ".pdf") {
type = "application/pdf";
} else if(ext == ".gif") {
type = "application/gif";
} else if(ext == ".jpeg") {
type = "application/jpeg";
} else if(ext == ".png") {
type = "application/png";
} else if(ext == ".mpeg") {
type = "application/mpeg";
}else if(ext == '.zip'){
return false
}
var myFsRootDirectory1 = decodeURI(fileEntry.nativeURL)
cordova.plugins.fileOpener2.open(myFsRootDirectory1, type, {
error: function(e) {


},
success: function() {
}
});
} catch(e) {
alert("try:  " + e)
}
}
})
};


fileWriter.onerror = function (e) {
Vue.$vux.loading.hide()
console.log("Failed file read: " + e.toString());
};


if (isAppend) {
try {
fileWriter.seek(fileWriter.length);
}
catch (e) {
console.log("file doesn't exist!");
}
}
fileWriter.write(dataObj);
});
},
}
export default lisUtils;


