
import Previewer from 'vux/src/components/previewer/index.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Loading from 'vux/src/components/loading/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonGet } from '../assets/js/getData'
export default {
data (){
return {
tip: '',
loading: false,
loading_s: true,
isGetMsg: false,
currentPage: 1,
pageSize: 5,
pageList: [],
showLoading: false,
show1: false,
text: '',
unitItem: this.$route.query.unitItem,
ticketId: this.$route.query.ticketId,
imgList: [],
options: {
getThumbBoundsFn (index) {
let thumbnail = document.querySelectorAll('.previewer-demo-img')[index]
let pageYScroll = window.pageYOffset || document.documentElement.scrollTop
let rect = thumbnail.getBoundingClientRect()
return {x: rect.left, y: rect.top + pageYScroll, w: rect.width}
}
},
}
},
created (){
this.getPageList()
},
mounted (){},
directives: {
TransferDom
},
components: {
LoadMore,
Scroller,
Loading,
Confirm,
Previewer,
XHeader
},
methods: {
closePreview (){
this.imgFlag = true
},
show (index,index1) {
this.imgList = []
let data = {
msrc: this.pageList[index].list[index1].signPictrue,
src: this.pageList[index].list[index1].signPictrue
}
this.imgList.push(data)
this.$refs.previewer.show(0)
},
back() {
this.$router.go(-1)
},
query (){
this.currentPage = 1
this.getPageList()
},

getPageList (){
let _this = this
let params = {
current: _this.currentPage,
size: _this.pageSize,
ticketId: _this.ticketId,
unitType: _this.unitItem.unitType
}
_this.showLoading = true
let urls = 'saferisk/risk/work/dgdw/timeLine'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.pageList = res.data
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
onScrollBottom (){
}
}
}



