import Vue from 'vue'
import Vuex from 'vuex'
Vue.use(Vuex)

const store = new Vuex.Store({
	state: {
		msgNum: 0,
		showTab: true,
		qcAlive: true,//风险清册
		sjfxAlive: true,//三级及以上风险清册
		bookAlive: true,//一本账
		workAlive: true,//风险预警 
		noticeAlive: true,//风险通知单 
		manageAlive: true,//风险作业管控 
		platform: true,//手机是否是安卓
		qcJgAlive: true,//清册工程列表
		sjfxJgAlive: true,//三级清册工程列表
		workJgAlive: true,//三级清册工程列表
		ip: '',
		port: '',
		riskTicket: true,
		riskTicketMain: true,
		riskTicketPart: true,
		riskTicketList: true,
	},
	getters: {
		getMsgNum (state){
			return state.msgNum
		},
		getShowTab (state){
			return state.showTab
		},
		getQcAlive (state){
			return state.qcAlive
		},
		getSjfxAlive (state){
			return state.sjfxAlive
		},
		getBookAlive (state){
			return state.bookAlive
		},
		getWorkAlive (state){
			return state.workAlive
		},
		getNoticeAlive (state){
			return state.noticeAlive
		},
		getManageAlive (state){
			return state.manageAlive
		},
		getPlatform (state){
			return state.platform
		},
		getQcJgAlive (state){
			return state.qcJgAlive
		},
		getSjfxJgAlive (state){
			return state.sjfxJgAlive
		},
		getWorkJgAlive (state){
			return state.workJgAlive
		},
		getIp (state){
			return state.ip
		},
		getPort (state){
			return state.port
		},
		getRiskTicketAlive (state){
			return state.riskTicket
		},
		getRiskTicketMainAlive (state){
			return state.riskTicketMain
		},
		getRiskTicketPartAlive (state){
			return state.riskTicketPart
		},
		getRiskTicketListAlive (state){
			return state.riskTicketList
		}
	},
	mutations: {
		setMsgNum (state,data){
			state.msgNum = data
		},
		setShowTab (state,data){
			state.showTab = data
		},
		setQcAlive (state,data){
			state.qcAlive = data
		},
		setSjfxAlive (state,data){
			state.sjfxAlive = data
		},
		setBookAlive (state,data){
			state.bookAlive = data
		},
		setWorkAlive (state,data){
			state.workAlive = data
		},
		setNoticeAlive (state,data){
			state.noticeAlive = data
		},
		setManageAlive (state,data){
			state.manageAlive = data
		},
		setPlatform (state,data){
			state.platform = data
		},
		setQcJgAlive (state,data){
			state.qcJgAlive = data
		},
		setSjfxJgAlive (state,data){
			state.sjfxJgAlive = data
		},
		setWorkJgAlive (state,data){
			state.workJgAlive = data
		},
		setIp (state,data){
			state.ip = data
		},
		setPort (state,data){
			state.port = data
		},
		setRiskTicketAlive (state,data){
			state.riskTicket = data
		},
		setRiskTicketMainAlive (state,data){
			state.riskTicketMain = data
		},
		setRiskTicketPartAlive (state,data){
			state.riskTicketPart = data
		},
		setRiskTicketListAlive (state,data){
			state.riskTicketList = data
		}
	},
	action: {
		setMsgNum (context,data){
			context.commit('setMsgNum',data)
		},
		setShowTab (context,data){
			context.commit('setShowTab',data)
		},
		setQcAlive (context,data){
			context.commit('setQcAlive',data)
		},
		setSjfxAlive (context,data){
			context.commit('setSjfxAlive',data)
		},
		setBookAlive (context,data){
			context.commit('setBookAlive',data)
		},
		setWorkAlive (context,data){
			context.commit('setWorkAlive',data)
		},
		setNoticeAlive (context,data){
			context.commit('setNoticeAlive',data)
		},
		setManageAlive (context,data){
			context.commit('setManageAlive',data)
		},
		setPlatform (context,data){
			context.commit('setPlatform',data)
		},
		setQcJgAlive (context,data){
			context.commit('setQcJgAlive',data)
		},
		setSjfxJgAlive (context,data){
			context.commit('setSjfxJgAlive',data)
		},
		setWorkJgAlive (context,data){
			context.commit('setWorkJgAlive',data)
		},
		setIp (context,data){
			context.commit('setIp',data)
		},
		setPort (context,data){
			context.commit('setPort',data)
		},
		setRiskTicketAlive (context,data){
			context.commit('setRiskTicketAlive',data)
		},
		setRiskTicketMainAlive (context,data){
			context.commit('setRiskTicketMainAlive',data)
		},
		setRiskTicketPartAlive (context,data){
			context.commit('setRiskTicketPartAlive',data)
		},
		setRiskTicketListAlive (context,data){
			context.commit('setRiskTicketListAlive',data)
		}
	}
})
export default store



