
import Cell from 'vux/src/components/cell/index.vue'
import Tab from 'vux/src/components/tab/tab.vue'
import TabItem from 'vux/src/components/tab/tab-item.vue'
import XTextarea from 'vux/src/components/x-textarea/index.vue'
import Checker from 'vux/src/components/checker/checker.vue'
import XTable from 'vux/src/components/x-table/index.vue'
import CheckerItem from 'vux/src/components/checker/checker-item.vue'
import XHeader from 'vux/src/components/x-header/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XInput from 'vux/src/components/x-input/index.vue'
import LoadMore from 'vux/src/components/load-more/index.vue'
import Scroller from 'vux/src/components/scroller/index.vue'
import PopupPicker from 'vux/src/components/popup-picker/index.vue'
import Selector from 'vux/src/components/selector/index.vue'
import XButton from 'vux/src/components/x-button/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import Popup from 'vux/src/components/popup/index.vue'
import Loading from 'vux/src/components/loading/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import Confirm from 'vux/src/components/confirm/index.vue'

import { commonAjax, commonGet,commonDelete,commonPost } from '../assets/js/getData'
import Session from '../store/session'
import Store from '../store/store'
import { mapGetters } from 'vuex'
import echarts from 'echarts'
export default {
data (){
return {
showDialogStyle: false,
showLoading: false,
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
text: '',
totals:10,
loading: false,
loading_s: true,
isGetMsg: false,
tip: '暂无数据',
currentPage:1,
showContent003:false,
pageSize:10,
demo2: '',
ticketType: 0,
demo10:'',
show1:false,
partName:[],
searchList:'',
showList:false,
statistics:{},
heardList:{},
list2:[
{name: '风险作业明细',value: '0'},
{name: '近一周风险趋势',value: '1'},
],
list:[],
pageList: [],
charts: '',
opinion:['男','女'],
opinionData:[
{value:335, name:'男'},
{value:310, name:'女'},

]

}
},
created (){
this.statistics = this.$route.query.item
console.log(this.statistics)
this.$store.commit('setShowTab',false)
this.getSgsList()
if(this.statistics == undefined){
this.getSgsLists()
}
},
mounted() {
this.$nextTick(() => {
this.getEachat()
});
},
methods:{

getSgsLists (){
let _this = this

let unitIds = ''
if(_this.statistics == undefined){
unitIds = _this.peopList.baseInfo.unitId
}else{
unitIds = _this.statistics.unitId
}
let params = {
unitId:unitIds
}
let urls = 'saferisk/risk/analysis/unitList'
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.heardList = res.data.unitRiskList[0]
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
getEachat(){
let _this = this
let urls = 'saferisk/risk/analysis/week'
let unitIds = ''
if(_this.statistics == undefined){
unitIds = _this.peopList.baseInfo.unitId
}else{
unitIds = _this.statistics.unitId
}
let params = {
unitId:unitIds
}
let time = []
let riskOne = []
let riskTwo = []
let riskThree = []
let riskFour = []
commonGet(urls,params,function(res){
if(res.code == 200){
res.data.forEach(item => {
if(item.level == 1){
item.unitRiskStatisList.forEach(item1 => {
time.push(item1.time)
riskOne.push(item1.num)
})
}else if(item.level == 2){
item.unitRiskStatisList.forEach(item1 => {
riskTwo.push(item1.num)
})
}else if(item.level == 3){
item.unitRiskStatisList.forEach(item1 => {
riskThree.push(item1.num)
})
}else if(item.level == 4){
item.unitRiskStatisList.forEach(item1 => {
riskFour.push(item1.num)
})
}
})
console.log(time)
console.log(riskOne)

let myChart = echarts.init(document.getElementById('myChart'));
let option = {}

option = {
title: {
text: '',
subtext: ''
},
tooltip: {
trigger: 'axis'
},
legend: {
data:['一级风险','二级风险','三级风险','四级风险']
},
xAxis:  {
type: 'category',
boundaryGap: false,
data: time
},
yAxis: {
type: 'value',
axisLabel: {
formatter: '{value}'
}
},
series: [
{
name:'一级风险',
type:'line',
data:riskOne,

markPoint: {
data: [
{type: 'max', name: '最大值'},
{type: 'min', name: '最小值'}
]
},
},
{
name:'二级风险',
type:'line',
data:riskTwo,

markPoint: {
data: [
{type: 'max', name: '最大值'},
{type: 'min', name: '最小值'}
]
},
},
{
name:'三级风险',
type:'line',
data:riskThree,

markPoint: {
data: [
{type: 'max', name: '最大值'},
{type: 'min', name: '最小值'}
]
},
},
{
name:'四级风险',
type:'line',
data:riskFour,

markPoint: {
data: [
{type: 'max', name: '最大值'},
{type: 'min', name: '最小值'}
]
},
}
]
}
myChart.setOption(option);
}
})
},
query(){
this.currentPage = 1
this.getSgsList()
},
lookDetail(item){
let _this = this
_this.showLoading = true
console.log(item)
let urls = 'saferisk/risk/analysis/partList'
let params = {
riskWorkId:item.id
}
commonGet(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
if(res.data.length>0){
_this.showList = true
_this.partName = res.data
}else{
_this.show1 = true
_this.text = '暂无作业部位及开展情况！'
}

}
})
},
onItemClick(){

},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.getSgsList()
_this.isGetMsg = false
}else{
return false
}
},
back (){
this.$router.go(-1)

},
getSgsList (){
let _this = this
let params = {
current: _this.currentPage,
size: _this.pageSize,
unitId:_this.statistics !=undefined ? _this.statistics.unitId : _this.peopList.baseInfo.unitId,
projectName:_this.searchList,
}
_this.showLoading = true
let urls = 'saferisk/risk/analysis/projectList'
commonGet(urls,params,function(res){
if(res.code == 200){
res.data.records.forEach(item => {
_this.$set(item,'direction',false)
});
_this.totals = res.data.total
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.pageList = res.data.records
}else{
_this.pageList = _this.pageList.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.pageList = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
}
_this.loading = false
_this.showLoading = false
})
},
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
Tab,
TabItem,
Cell,
XTable,
},
}



