searchFace (formData,type){
let _this = this
let urls = 'workticket/aipFace/aipFaceSearch'
commonPost(urls,formData,function(res){
if(res.code == 200){
if(res.data){
if(res.data.signUrl,type){
if(res.data.id == _this.peopList.baseInfo.id){
_this.getPeopName(res.data.signUrl)
}else{
_this.show1 = true
_this.text = '当前人员与登录人员不匹配，请重新识别'
}
}else{
_this.show1 = true
_this.text = '请维护签名照片'
}
}else{
_this.show1 = true
_this.text = '未识别出当前人员，请重新识别'
}
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

getPeopName (signUrl,type){
let _this = this
let params = {}
let url = '/oss/api/v1/files/'+signUrl
commonGet(url,params,function(res){
if(res.code == 200){
for(let i in _this.riskWorkSignList){
if(_this.riskWorkSignList[i].peopType == type){
_this.riskWorkSignList[i].src = res.data.imageUrl
_this.riskWorkSignList[i].attachId = res.data.id
}
}
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

