init (longitude,latitude){
let _this = this
let lnglat = longitude + ',' + latitude
let lnglatList =  lnglat.split(',')
let map = new AMap.Map('container', {

center: lnglatList,
resizeEnable: true,
zoom: 10,
lang: 'zh-cn'
})

let marker = new AMap.Marker({


});
map.add(marker);



marker.setPosition(lnglatList);
var markerContent = document.createElement("div");
var markerImg = document.createElement("img");
markerImg.className = "markerlnglat";

markerImg.src = require('../assets/img/ic_position_red.png')
markerContent.appendChild(markerImg);
marker.setContent(markerContent); 

AMap.plugin(['AMap.ToolBar', 'AMap.Scale'], function () {
map.addControl(new AMap.ToolBar())
map.addControl(new AMap.Scale())
})
},

setPosition (){
let _this = this
var map = new AMap.Map('container', {
resizeEnable: true
});
AMap.plugin('AMap.Geolocation', function() {
var geolocation = new AMap.Geolocation({
enableHighAccuracy: true,//是否使用高精度定位，默认:true
timeout: 10000,          //超过10秒后停止定位，默认：5s
zoomToAccuracy: true,   //定位成功后是否自动调整地图视野到定位点
resizeEnable: true,
zoom: 10,
lang: 'zh-cn'
});
map.addControl(geolocation);
geolocation.getCurrentPosition(function(status,result){
if(status=='complete'){
_this.init(result.position.lng,result.position.lat)
_this.siteName = result.formattedAddress + '。'+ '经度：'+result.position.lng + ','+ '纬度：'+result.position.lat
_this.latitude = result.position.lat
_this.longitude = result.position.lng
console.log(_this.workPartData)
}else{
console.log(result.message)
}
});
});
},
openApp(){
let lng = ''
let lat = ''
lng = this.longitude
lat = this.latitude
if (lng == '' || lat == '') {
AlertModule.show({
title: '提示',
content: '请定位！',
})
return false;
}
let schemeIntent;   
if(device.platform === 'Android') {
schemeIntent = 'com.autonavi.minimap';
appAvailability.check(schemeIntent,function () {

let uri = ''
if (lat && lng) {
uri = "amapuri://route/plan/?sourceApplication=softname&dlat=" + lat + "&dlon=" + lng + "&dev=0&style=2"
}
var sApp = startApp.set({ /* params */
"action":"ACTION_VIEW",
"category":"CATEGORY_DEFAULT",
"type":"text/css",
"package":schemeIntent,
"uri":uri,
"flags":["FLAG_ACTIVITY_CLEAR_TOP","FLAG_ACTIVITY_CLEAR_TASK"],
"intentstart":"startActivity"
}, { /* extras */
"EXTRA_STREAM":"extraValue1",
"extraKey2":"extraValue2"
});
sApp.start(function() { /* success */
}, function(error) { /* fail */
});
},function () {
AlertModule.show({
title: '提示',
content: '请安装高德地图！',
})
});
} else {
schemeIntent = 'iosamap://'
let uri = "iosamap://path?sourceApplication=applicationName&did=BGVIS2&dlat=" + lat + "2&dlon=" + lng + "&dev=0&style=2";
LocationServicePlugin.canOpenGaode(schemeIntent,function(obj) { /* success */
LocationServicePlugin.openGaode(uri,function(obj) { /* success */
}, function(error) { /* fail */
})
}, function(error) { /* fail */
AlertModule.show({
title: '提示',
content: '请安装高德地图！',
})
})
}
},

geoCode(address) {
let _this = this
let geocoder = new AMap.Geocoder({

})
geocoder.getLocation(address, function(status, result) {
if (status === 'complete'&&result.geocodes.length) {
let lnglat = result.geocodes[0].location
_this.init(lnglat.lng,lnglat.lat)
for(let i in _this.workPartData){
if(_this.workPart[0] == _this.workPartData[i].value){
_this.workPartData[i].longitude = lnglat.lng
_this.workPartData[i].latitude = lnglat.lat
}
}
}else{
_this.tip = '根据地址查询位置失败';
_this.tipType='cancel'
_this.showTip = true;
}
});
},

regeoCode(longitude,latitude) {
let _this = this
let lnglat = longitude + ',' + latitude
let lnglatList =  lnglat.split(',')
_this.init(longitude,latitude)
let geocoder = new AMap.Geocoder({
})
geocoder.getAddress(lnglatList, function(status, result) {
if (status === 'complete'&&result.regeocode) {
let address = result.regeocode.formattedAddress;
_this.partName = address
}else{
_this.tip = '根据经纬度查询地址失败';
_this.tipType='cancel'
_this.showTip = true;
}
});
},
showmore(){
this.showMenus = !this.showMenus;
this.showDialogStyle = !this.showDialogStyle;
},

clickSpan (id,type){
if(type == 'can'){
for(let i in this.seachSpanList){
if(id != this.seachSpanList[i].id){
this.seachSpanList[i].isChoose = false
}else{
this.seachSpanList[i].isChoose = true
this.seachId = this.seachSpanList[i].id
this.riskLevel = this.seachSpanList[i].id
}
}
}else{
if(this.canHandle){
for(let i in this.seachSpanList){
if(id != this.seachSpanList[i].id){
this.seachSpanList[i].isChoose = false
}else{
this.seachSpanList[i].isChoose = true
this.seachId = this.seachSpanList[i].id
this.riskLevel = this.seachSpanList[i].id
}
}
}
}
},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},

onItemClick (value, disabled) {
let _this = this
this.commonList.forEach(e=>{
if(e.key == value){
_this.$set(e,'ckecked',true)
