
import XHeader from 'vux/src/components/x-header/index.vue'
import Cell from 'vux/src/components/cell/index.vue'
import Group from 'vux/src/components/group/index.vue'
import XDialog from 'vux/src/components/x-dialog/index.vue'
import TransferDom from 'vux/src/directives/transfer-dom/index.js'
import XInput from 'vux/src/components/x-input/index.vue'

import Session from '../store/session'
export default {
directives: {
TransferDom
},
components: {
XHeader,
Cell,
Group,
XInput,
XDialog
},
data() {
return {
searchProject: '',
list:[],
peopList:[],
peopList_jg:{},
authorizationList:{},
show:false,
}
},
created() {
this.$store.commit('setShowTab',true)
if(Session.fetch('peopList').length>0){
if(Session.fetch('peopList')[0].baseInfo.workTicketLevel == 12 || Session.fetch('peopList')[0].baseInfo.workTicketLevel == 11){

}else{
this.peopList = Session.fetch('peopList')
}
}
this.peopList_jg = Session.fetch('peopList_jg')
},
mounted() {
},
methods: {
showMine(){
if(this.peopList.length == 0){
return false
}
if (this.peopList.length>1 || this.peopList_jg) {
this.show = true
}else{
this.show = false
}
},
getName(obj){
if (obj.departName) {
return obj.sectionName+"-"+obj.departName+"-"+obj.baseInfo.postcodeName
} else if (obj.postcodeName){
return obj.sectionName+"-"+obj.baseInfo.postcodeName
}else{
return obj.sectionName
}
},
getTitle (obj){
if(obj.project){
return obj.project.name
}else{
return ''
}
},
selectPower(obj){
this.show = false
this.$store.commit('setQcAlive',false)
this.$store.commit('setSjfxAlive',false)
this.$store.commit('setBookAlive',false)
this.$store.commit('setWorkAlive',false)
this.$store.commit('setNoticeAlive',false)
Session.save('authorizationList',obj)
},
back() {
navigator.app.exitApp();
},
searchProjectFun (){
this.peopList.forEach(item => {
item.baseInfo.isShow = false
})
if(this.searchProject == ''){
for(let i in this.peopList){
this.peopList[i].baseInfo.isShow = true
}
return false
}
let item = []
item = this.peopList.filter(item =>
item.project && Object.keys(item.project).length>0 && item.project.name.indexOf(this.searchProject) !== -1
)
for(let i in this.peopList){
this.peopList[i].baseInfo.isShow = false
for(let j in item){
if(this.peopList[i].id == item[j].id){
this.peopList[i].baseInfo.isShow = true
}
}
}

}
},
watch: {
searchProject (newVal,oldVal){
this.searchProjectFun()
}
}
}



