methods: {
timeChange (){
this.weekTime = []
this.weekData = []
let year = getDate(this.workStartTime,'yyyy')
let month = getDate(this.workStartTime,'m')
this.weekData = this.getYMWeek(year,month)
},

getYMWeek(year, month) {
let list = [];
let d1;
let weekCount;
let d = new Date();

d.setFullYear(year, month-1, 1); 
let w1 = d.getDay(); 
if (w1 === 0) w1 = 7; 

d.setFullYear(year, month, 0); 
let dd = d.getDate(); 


if (w1 !== 1) {
d1 = (7-w1)+2;
} else {
d1 = 1;
}
weekCount = Math.ceil(((dd-d1)+1)/7); 
for (let i = 0; i < weekCount; i+=1 ) {
let monday = d1+(i*7); 
let sunday = monday + 6; 
let from = month+"-"+ monday;
let to;
if (sunday <= dd) {
to = month+"-"+ sunday;
} else {
d.setFullYear(year, month-1, sunday);
to = (d.getMonth()+1)+"-"+d.getDate();
}
let month1 = month
let monday1 = monday
if (month < 10) month1 = '0' + month;
if (monday < 10) monday1 = '0' + monday;
let json = {
'year':year,
'month':month,
'week':i+1,
'name':from + "~" + to,
'value': year + '-' + month1 + '-' + monday1
};
list.push(json);
}
return list;
},
