import lisUtils from '../assets/js/units.js'
import { mapGetters } from 'vuex'
export default {
data (){
return {
seachSpanList: [
{text: '全部',id: '',isChoose: true},
{text: '一级',id: '1',isChoose: false},
{text: '二级',id: '2',isChoose: false},
{text: '三级',id: '3',isChoose: false},
{text: '四级',id: '4',isChoose: false},
],
seachId: '',
searchTime: '',
unitData: [],//建管单位
projectData: [],//工程
programName: '',
unitId: [],
unitName: '',
projectName: '',
projectId: [],
totals: 0,
tip: '暂无数据',
loading: false,
loading_s: true,
isGetMsg: false,
searchFlag: false,
currentPage: 1,
pageSize: 5,
pageList: [],
showLoading: false,
routeItem: '',
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
show1: false,
text: '',
unitFlag: false,
proFlag: false,
sectionId: '',
platform: true,
typeData: [{name: '全部',value: ''},{name: '一般',value: '0'},{name: '专项',value: '1'}],
showMenus: false,
showDialogStyle: false,
postId: '',
departId: '',
canHandle: false,
canReview: false,
searchItem: '',
isSgs: false

}
},
created (){
this.$store.commit('setShowTab',true)
if (device.platform != 'Android') this.platform = false
this.routeItem = this.$route.query.routeItem ? JSON.parse(this.$route.query.routeItem): ''
this.searchItem = this.$route.query.searchItem ? JSON.parse(this.$route.query.searchItem): ''
this.imitPage()
},
activated (){
if(this.bookAlive){
this.$store.commit('setShowTab',true)
}else{
this.$store.commit('setShowTab',true)
Object.assign(this.$data, this.$options.data())
if (device.platform != 'Android') this.platform = false
this.routeItem = this.$route.query.routeItem ? JSON.parse(this.$route.query.routeItem): ''
this.searchItem = this.$route.query.searchItem ? JSON.parse(this.$route.query.searchItem): ''
this.imitPage()
this.$store.commit('setBookAlive',true)
}
},
computed:{
...mapGetters({
bookAlive: 'getBookAlive',

})
},
mounted (){},
filters: {
setNodeName (val){
if(val){
if(val == '25'){
return '编辑中'
}else if(val == '26'){
return '业主/管理部审核'
}else if(val == '27'){
return '建管单位审核'
}else if(val == '27'){
return '审核通过'
}
}else{
return ''
}
}
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
PopupPicker,
Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Datetime,
},
methods: {

chooseBook (item){
item.isChoose = !item.isChoose
},

chooseAll (){
for(let i in this.pageList){
this.pageList[i].isChoose = true
}
},

down(item){
let _this = this;
this.$vux.loading.show({
text: '加载中...'
})


var name=item.downloadFileName+".xls"
let params = {
id: item.id
}
let urls = 'saferisk/risk/ybz/export'
commonDown(urls,params,function(res){
let blob = new Blob([res], {
type: ''
})
let objectUrl = blob
lisUtils.createDir('', function(dirEntry) {
var configPath = dirEntry.fullPath + name
window.resolveLocalFileSystemURL(cordova.file.externalRootDirectory, function (root) {

root.getFile(configPath, {
create: true,
exclusive: false
},
function(fileEntry) {
fileEntry.file(function (file) {
var reader = new FileReader()
reader.onloadend = function() {

lisUtils.writeFile(fileEntry, objectUrl, false, configPath)
};
reader.readAsText(file);
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
})
})
},

downAll (){
let _this = this
this.showMenus = false
this.showDialogStyle = false
let params = {

}
let urls = 'youotech-saferisk/risk/ybz/export/name'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.downAllLoad(res.data)
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
downAllLoad(name1){
let _this = this;
this.$vux.loading.show({
text: '加载中...'
})
var name=name1+".xls"
let params = {
}
let urls = ''
if(_this.isSgs){
let ids = []
for(let i in _this.pageList){
if(_this.pageList[i].isChoose){
ids.push(_this.pageList[i].id)
}
}
params = {
ids: ids.join(',')
}
urls = 'youotech-saferisk/risk/ybz/select/export'
}else{
params = {
jsglUnitId: _this.unitId.length>0?_this.unitId[0]: '',
projectId: _this.projectId.length>0?_this.projectId[0]: '',
time: _this.searchTime
}
urls = 'saferisk/risk/ybz/export'
}
commonDown(urls,params,function(res){
let blob = new Blob([res], {
type: ''
})
let objectUrl = blob
lisUtils.createDir('', function(dirEntry) {
var configPath = dirEntry.fullPath + name
window.resolveLocalFileSystemURL(cordova.file.externalRootDirectory, function (root) {

root.getFile(configPath, {
create: true,
exclusive: false
},
function(fileEntry) {
fileEntry.file(function (file) {
var reader = new FileReader()
reader.onloadend = function() {

lisUtils.writeFile(fileEntry, objectUrl, false, configPath)
};
reader.readAsText(file);
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
}, function (error) {console.log(error) })
})
})
},
download(fileEntry, url) {
let _this = this;
var ft = new FileTransfer();
var fileURL = fileEntry.nativeURL;
ft.download(encodeURI(url), fileURL, function (entry) {
_this.$vux.loading.hide()


AlertModule.show({
title: '提示',
content: "下载成功!位置："+decodeURI(entry.nativeURL),
onHide () {
try {
var name = entry.name;
var ext = name.substr(name.lastIndexOf("."));
var type = 'application/vnd.android.package-archive';
if(ext == ".doc" || ext == ".docx" || ext == ".xls" || ext == ".xlsx") {
type = "application/msword";
} else if(ext == ".pdf") {
type = "application/pdf";
} else if(ext == ".gif") {
type = "application/gif";
} else if(ext == ".jpeg") {
type = "application/jpeg";
} else if(ext == ".png") {
type = "application/png";
} else if(ext == ".mpeg") {
type = "application/mpeg";
}else if(ext == '.zip'){
return false
}
var myFsRootDirectory1 = decodeURI(entry.nativeURL)
cordova.plugins.fileOpener2.open(myFsRootDirectory1, type, {
error: function(e) {


},
success: function() {
}
});
} catch(e) {

}
}
})
}, function (err) {
console.log(err)
_this.$vux.loading.hide()
_this.show1 = true
_this.text = "下载失败"
}, null,{
});
},



clickSpan (id){
for(let i in this.seachSpanList){
if(id != this.seachSpanList[i].id){
this.seachSpanList[i].isChoose = false
}else{
this.seachSpanList[i].isChoose = true
this.seachId = this.seachSpanList[i].id
}
}
},

submitAll (){
this.nogn()
},

toSubmit (item){
let _this = this
_this.showLoading = true
let params = {
id: item.id,
state: item.state,
type: 'submit'
}
let urls = 'youotech-saferisk/risk/discern/inventory/check'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.query()
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

rollback (item){
let _this = this
_this.showLoading = true
let params = {
id: item.id,
state: item.state,
type: '2'
}
let urls = 'youotech-saferisk/risk/discern/inventory/check'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.query()
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
toDetail (item){
this.$router.push({path: '/addRiskBook',query: {id: item.id,isDetail: true}})
},
toAdd (item,type){
this.$router.push({path: '/addRiskBook',query: {id: item.id,pageType: type}})
},
toAddRiskBook (){
this.showMenus = false;
this.showDialogStyle = false;
this.$router.push({path: '/addRiskBook',query: {pageType: 'edit'}})
},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
showmore(){
this.showMenus = !this.showMenus;
this.showDialogStyle = !this.showDialogStyle;
},

peopPower (item){//true 为没权限
if(this.canReview){
if(item.nodeId == '25'){//编制
return true
}else if(item.nodeId == '26'){//业主审核
if(this.peopList.baseInfo.workTicketLevel == 10 && (this.peopList.baseInfo.postcode == '6' || this.peopList.baseInfo.postcode == '7')){
return false
}else if(this.peopList.baseInfo.postcode == '401' || this.peopList.baseInfo.postcode == '402'){
return false
}else{
return true
}
}else if(item.nodeId == '27'){//建管单位审核
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 22){
return false
}else{
return true
}
}else if(item.nodeId == '28'){//审核通过
return true
}else{
return true
}
}else{
return true
}
},

setEdit (item){//true 为没权限
if(this.canHandle){
if(item.nodeId == '25'){
if(this.peopList.baseInfo.unitType == 'sg' && this.peopList.baseInfo.postcode == '4'){//编制权限
return false
}else{
return true
}
}else{
return true
}
}else{
return true
}
},
imitPage (){
if((this.peopList.baseInfo.unitType == 'sg' || this.peopList.baseInfo.unitType == 'fb') && this.peopList.baseInfo.postcode == '4'){//编制权限
this.canHandle = true
this.canReview = false
}
if(this.peopList.baseInfo.workTicketLevel == 10 && (this.peopList.baseInfo.postcode == '6' || this.peopList.baseInfo.postcode == '7')){//审核权限
this.canHandle = false
this.canReview = true
}
if(this.peopList.baseInfo.postcode == '401' || this.peopList.baseInfo.postcode == '402'){
this.canHandle = false
this.canReview = true
}
if(this.peopList.baseInfo.unitType == 'sgs'){//审核权限
this.canHandle = false
this.canReview = false
}
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 22){
this.canHandle = false
this.canReview = true
}
if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.workTicketLevel == 22) {
if(this.searchItem){
this.unitData = [{
name:this.searchItem.unitName,
value:this.searchItem.unitId.toString()
}]
this.unitId = [this.searchItem.unitId.toString()]
this.searchTime = this.searchItem.time
this.isSgs = true
}else{
this.getOrg()
this.unitFlag = false
}
}else{
if(this.peopList.baseInfo.unitType == 'jg' && this.peopList.baseInfo.workTicketLevel == 11){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
}else{
if(!this.peopList.project){
this.unitData = [{
name:this.peopList.baseInfo.unitName,
value:this.peopList.baseInfo.unitId.toString()
}]
this.unitId = [this.peopList.baseInfo.unitId.toString()]
this.unitFlag = true
}else{
this.postId = this.peopList.baseInfo.postcode
this.unitData = [{
name:this.peopList.project.unitName,
value:this.peopList.project.unitId.toString()
}]
this.unitId = [this.peopList.project.unitId.toString()]
this.unitFlag = true
}
}

}
if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.unitType == 'jg' || this.peopList.baseInfo.workTicketLevel == 22) {
if(this.peopList.baseInfo.workTicketLevel == 10){
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
}else if(this.peopList.baseInfo.workTicketLevel == 21){
if(!this.peopList.project){
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
}
}else{
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}
}else{
if(!this.peopList.project){
this.proFlag = false
if (this.unitFlag || this.unitId.length>0) {
this.getProjects()
}
}else{
this.proFlag = true
this.sectionId = this.peopList.sectionId
this.projectData = [{
name:this.peopList.project.name,
value:this.peopList.project.id.toString()
}]
this.projectId = [this.peopList.project.id.toString()]
}
}

this.query()

},

getOrg (){
let _this = this
let params = {

}
let urls = 'pms/api/v1/units/list/org/current-user'
commonGet(urls,params,function(res){
if(!res.status && res){
_this.unitData = res.map((item) => {
return {name: item.name,value: item.id.toString()}
})
if(_this.peopList.baseInfo.workTicketLevel == 22 && _this.unitData.length == 1){
_this.unitId = [res[0].id.toString()]
_this.getProjects()
}
if (_this.unitData.length == 1) {
_this.unitFlag = true
}
if(_this.routeItem){
_this.unitId = [_this.routeItem.buildUnitId.toString()]
}
}
})
},
changeUnit (){
this.getProjects()
this.projectId = []
},

getProjects (){
let _this = this
let params = {

}
_this.projectData = []
let urls = 'pms/api/v1/unit_projects/list/unit/'+_this.unitId[0]
commonGet(urls,params,function(res){
if(!res.status && res){



_this.projectData = []
for(let i in res){
if(res[i].pid != '0'){
let item = {name: res[i].name,value: res[i].id.toString()}
_this.projectData.push(item)
}
}









if(_this.routeItem){
_this.projectId = [_this.routeItem.projectId.toString()]
}
}
})
},

deleteMsg (id){
let _this = this
_this.showLoading = true
let params = {
}
let urls = 'youotech-saferisk/risk/discern/inventory/delete?id='+id
commonDelete(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
_this.query()
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

query (num){
if(num != 1){
this.searchFlag = false
this.showDialogStyle = false
}
this.currentPage = 1
this.getPageList()
},
cancel (){
this.searchFlag = false
this.showDialogStyle = false
},

showSearch (){
this.showMenus = false
this.searchFlag = !this.searchFlag
this.showDialogStyle = !this.showDialogStyle

},
onChangeUnit (val){
for(let i in this.unitData){
if(this.unitData[i].value == val){
this.unitName = this.unitData[i].name
}
}
},
onChangeProject (val){
for(let i in this.projectData){
if(this.projectData[i].value == val){
this.projectName = this.projectData[i].name
}
}
},

getPageList (){
let _this = this
_this.onChangeUnit(_this.unitId[0])
_this.onChangeProject(_this.projectId[0])
let params = {
current: _this.currentPage,
size: _this.pageSize,
projectId: _this.projectId[0],
jsglUnitId: _this.unitId[0],
time: _this.searchTime,
isSgs: _this.isSgs ? 1: 0
}
_this.showLoading = true
let urls = 'youotech-saferisk/risk/ybz/pageList'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.totals = res.data.total
for(let i in res.data.records){
let flags = {
isChoose: true
}
res.data.records[i] = Object.assign(res.data.records[i],flags)
}
if(res.data.records.length > 0){
let num = _this.currentPage * _this.pageSize
if(res.data.total >= num){
_this.loading_s = false
_this.isGetMsg = true
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
if(_this.currentPage == 1){
_this.pageList = res.data.records
}else{
_this.pageList = _this.pageList.concat(res.data.records)
}
}else{
if(_this.currentPage == 1){
_this.pageList = res.data.records
_this.tip = '暂无数据！'
_this.loading_s = true
_this.isGetMsg = false
}else{
_this.tip = '暂无更多数据！'
_this.loading_s = true
_this.isGetMsg = false
}
}
if(res.data.records.length>0 && _this.currentPage == 1){
_this.$refs.scrollerBottom.reset({top: 0});
}
}else{
_this.tip = '出错啦！'
_this.loading_s = true
}
_this.loading = false
_this.showLoading = false
})
},

onScrollBottom (){
let _this = this
if(_this.isGetMsg){
_this.currentPage += 1
_this.loading = true
_this.loading_s = false
_this.getPageList()
_this.isGetMsg = false
}else{
return false
}
},
back (){
this.$router.go(-1)

}
}
}



