initPage (){
if((this.peopList.baseInfo.unitType == 'sg' || this.peopList.baseInfo.unitType == 'fb') && this.peopList.baseInfo.postcode == '4'){//编制权限
this.canHandle = true
if(this.id){
this.getDetail()
}else{
if(this.peopList.project.manageStyle == '1'){//存在项目管理部
this.isXmglb = true
}else{
this.isXmglb = false
}
this.getIsFirst(this.peopList.project.id,this.peopList.sectionId)
}
}else if(this.peopList.baseInfo.workTicketLevel == 10 && (this.peopList.baseInfo.postcode == '6' || this.peopList.baseInfo.postcode == '7')){//审核权限
this.canReview = true
if(this.id){
this.getDetail()
}
}else if(this.peopList.baseInfo.postcode == '401' || this.peopList.baseInfo.postcode == '402'){//审核权限
this.canReview = true
if(this.id){
this.getDetail()
}
}else if(this.peopList.baseInfo.unitType == 'sgs'){//审核权限
this.canReview = true
if(this.id){
this.getDetail()
}
}else{
if(this.id){
this.getDetail()
}
}
},

searchPart (){
if(this.searchPartValue == ''){
for(let i in this.partData){
this.partData[i].isShow = true
}
return false
}
let item = []
item = this.partData.filter(item =>
item.name.indexOf(this.searchPartValue) !== -1
)
for(let i in this.partData){
this.partData[i].isShow = false
for(let j in item){
if(this.partData[i].id == item[j].id){
this.partData[i].isShow = true
}
}
}
},

showPart (){
this.partId_copy = this.partId
this.searchPartValue = ''
this.searchPart()
this.partFlag = true
},

cancelPart (){
console.log(this.partId)
this.partFlag = false
this.partId = this.partId_copy
},

surePart (){
let index = 1
this.riskDetail.workPart = ''
for(let i in this.partData){
for(let j in this.partId){
if(this.partData[i].id == this.partId[j]){
this.riskDetail.workPart = this.riskDetail.workPart + ',' + this.partData[i].name
index++
}
}
}
this.riskDetail.workPart = this.riskDetail.workPart.substr(1)
this.partFlag = false
},

getPartList (projectId,sectionId){
let _this = this
_this.partData = []
let params = {
sectionId: sectionId
}
let urls = 'pms/api/v1/'+ projectId +'/towers/list'
commonGet(urls,params,function(res){
for(let i in res){
let item = {name: res[i].name,id: res[i].id+'',isShow: true}
_this.partData.push(item)
}
})
},

changeRadio (val, label){
console.log('change:', val, label)
},

toEdit (){
this.editFlag = true
this.newPreControl = this.riskDetail.newPreControlMeasure
this.$nextTick(()=>{
this.height = document.getElementById("body_height").clientHeight - 60
console.log(document.getElementById("body_height").clientHeight)
})

},

setPre (){
this.editFlag = false
this.riskDetail.newPreControlMeasure = this.newPreControl
this.riskDetail.preControlMeasure = this.newPreControl.replace(/\n/g,',')
},

setPosition (){
let _this = this
AMap.plugin('AMap.Geolocation', function() {
var geolocation = new AMap.Geolocation({

lang: 'zh-cn'
});
geolocation.getCurrentPosition(function(status,result){
if(status=='complete'){
_this.riskDetail.partName = result.formattedAddress + '。'+ '经度：'+result.position.lng + ','+ '纬度：'+result.position.lat
_this.riskDetail.latitude = result.position.lat
_this.riskDetail.longitude = result.position.lng
}else{
console.log(result.message)
_this.show1 = true
_this.text = result.message
}
});
});
},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
back (){
let _this = this
if(_this.pageType == 'edit'){
_this.$vux.confirm.show({

title: '提示',
content: '当前风险一本账尚未保存，确定返回？',
onCancel () {
},
onConfirm () {
_this.$store.commit('setShowTab',true)
_this.$router.go(-1)
}
})
}else{
_this.$store.commit('setShowTab',true)
_this.$router.go(-1)
}

}
},
watch: {
nextWeekRiskContentData (newVal,oldVal){
if(newVal.length>0){
this.nextWeekIsZtWorkId = ['1']
}else{
this.nextWeekIsZtWorkId = ['2']
}
},
nextWeekContentData (newVal,oldVal){
if(newVal.length>0){
this.nextWeekIsWorkId = ['1']
}else{
this.nextWeekIsWorkId = ['2']
}
}
}









}



