export default {
data (){
return {
searchPartValue: '',
partId: [],
partId_copy: [],
partFlag: false,
partData: [],
riskDetail:{},
mind: '',
showLoading: false,
peopList: Session.fetch('authorizationList'),
token: Session.fetch('token'),
show1: false,
text: '',
platform: true,
showMenus: false,
commonList: [
{key: '1',value: '是',ckecked:true,},
{key: '2',value: '否'},
],
radioValue: '1',
partName: '',
latitude: '',
longitude: '',
id: this.$route.query.id,
newPreControl: '',
editFlag: false,
height: 200,
canHandle: false,
canReview: false,
canChoose: false,
isDetail: this.$route.query.isDetail,
pageType: this.$route.query.pageType,
proType: '',
projectType: '',
provinceData: [],
provinceId: [],
departName: '',
departId: ''
}
},
created (){
this.$store.commit('setShowTab',false)
this.initPage()
this.getProvinceData()



},
mounted (){},







filters: {
},
directives: {
TransferDom
},
components: {
XHeader,
Group,
XInput,
LoadMore,
Scroller,
