Selector,
XButton,
Popup,
Loading,
XDialog,
Confirm,
Checker,
CheckerItem,
XTextarea,
Checklist,
Search
},
methods: {
autoSize (){
this.$nextTick(function(){
this.$refs.demoObject1.updateAutosize()
this.$refs.demoObject2.updateAutosize()
this.$refs.demoObject100.updateAutosize()
this.$refs.demoObject101.updateAutosize()
this.$refs.demoObject102.updateAutosize()
})
},
initPage (){
if(this.peopList.baseInfo.unitType == 'sg' || this.peopList.baseInfo.unitType == 'fb'){
if(this.peopList.departPid){//存在pid则为班组
this.departId = this.peopList.departPid
this.canHandle = false
this.canReview = false
}else{//项目部
this.departId = this.peopList.departId
if(this.peopList.baseInfo.workTicketLevel == 5 || this.peopList.baseInfo.workTicketLevel == 6 || this.peopList.baseInfo.postcode == '16' || this.peopList.baseInfo.postcode == '79' || this.peopList.baseInfo.postcode == '3' || this.peopList.baseInfo.postcode == '1'){
this.canHandle = true
this.canReview = false
this.departId = this.peopList.departId.toString()
this.departName = this.peopList.departName.toString()
}else{
this.canHandle = false
this.canReview = false
}
}
}else if(this.peopList.baseInfo.unitType == 'jl' || this.peopList.baseInfo.postcode == '6' || this.peopList.baseInfo.postcode == '7' || this.peopList.baseInfo.workTicketLevel == 21){
this.canHandle = false
this.canReview = true
}else{
this.canHandle = false
this.canReview = false
}
if (this.peopList.baseInfo.unitType == 'sgs' || this.peopList.baseInfo.unitType == 'jg' || this.peopList.baseInfo.workTicketLevel == 20) {
}else{




}
this.getDetail()
},

getProvinceData (){
let _this = this
let params = {

}
let urls = 'saferisk/system/dic/list'
commonGet(urls,params,function(res){
if(res.code == 200){
_this.provinceData = res.data.map(item => {
return {name: item.name,value: item.id.toString(),parent: item.pid.toString()}
})
console.log(_this.provinceData)
}
})
},

setTreeList (pid,data){
let arr = []
let list
for(let i in data){
let item = {children: []}
if(data[i].pid == pid){
item = Object.assign(data[i],item)
list = this.setTreeList(data[i].id,data)
arr.push(item)
if(list.length > 0){
arr[arr.length - 1].children = list
}
}
}
return arr
},

searchPart (){
if(this.searchPartValue == ''){
for(let i in this.partData){
this.partData[i].isShow = true
}
return false
}
let item = []
item = this.partData.filter(item =>
item.name.indexOf(this.searchPartValue) !== -1
)
for(let i in this.partData){
this.partData[i].isShow = false
for(let j in item){
if(this.partData[i].id == item[j].id){
this.partData[i].isShow = true
}
}
}
},

showPart (){
this.partId_copy = this.partId
this.searchPartValue = ''
this.searchPart()
this.partFlag = true
},

cancelPart (){
console.log(this.partId)
this.partFlag = false
this.partId = this.partId_copy
},

surePart (){
let index = 1
this.riskDetail.workPart = ''
this.riskDetail.partName = ''
for(let i in this.partData){
for(let j in this.partId){
if(this.partData[i].id == this.partId[j]){
this.riskDetail.workPart = this.riskDetail.workPart + ',' + this.partData[i].name
this.riskDetail.partName = this.riskDetail.partName + this.partData[i].name + '(经度:' + this.partData[i].longitude + ',纬度:' + this.partData[i].latitude + ')\r\n'
index++
}
}
}
this.riskDetail.workPart = this.riskDetail.workPart.substr(1)
this.riskDetail.workContent = this.riskDetail.workPart + this.riskDetail.workProcess

this.autoSize()
this.partFlag = false
},

getPartList (projectId,sectionId){
let _this = this
_this.partData = []
let params = {
sectionId: sectionId
}
let urls = 'pms/api/v1/'+ projectId +'/towers/list'
commonGet(urls,params,function(res){
for(let i in res){
let item = {name: res[i].name,id: res[i].id+'',isShow: true,latitude: res[i].latitude,longitude: res[i].longitude}
_this.partData.push(item)
}
})
},

onItemClick (value, disabled) {
let _this = this
this.commonList.forEach(e=>{
if(e.key == value){
_this.$set(e,'ckecked',true)
e.ckecked = true
}else{
this.$set(e,'ckecked',false)
e.ckecked = false
}
})
this.radioValue = value.toString()
},

toEdit (){
this.editFlag = true
this.newPreControl = this.riskDetail.newPreControlMeasure
this.$nextTick(()=>{
this.height = document.getElementById("body_height").clientHeight - 60
console.log(document.getElementById("body_height").clientHeight)
})

},

setPre (){
this.editFlag = false
this.riskDetail.newPreControlMeasure = this.newPreControl
this.riskDetail.preControlMeasure = this.newPreControl.replace(/\n/g,',')
},

submitMsg (){
let _this = this
_this.showLoading = true
let params = {
id: _this.riskDetail.id,
nodeId: _this.riskDetail.nodeId,
taskState: _this.radioValue
}
let urls = 'youotech-saferisk/risk/discern/inventory/check'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
if(_this.pageType == 'edit'){
_this.pageType = ''
_this.$store.commit('setQcAlive',false)
_this.back()
}else{
_this.$store.commit('setQcAlive',false)
_this.back()
}
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
saveAndSubmit (){
this.saveMsg('1')
},

saveMsg (type){
let _this = this
if((!_this.riskDetail.workPart && !_this.riskDetail.extendWorkPart) || !_this.riskDetail.workContent || !_this.riskDetail.siteDetail){// || _this.provinceId.length == 0
_this.text = '请正确填写每一项'
_this.show1 = true
return
}
_this.showLoading = true
let item = _this.partId.join(',')
let params = {
id: _this.riskDetail.id,
projectId: _this.riskDetail.projectId,
projectName: _this.riskDetail.projectName,
riskDbId: _this.riskDetail.riskDbId,
preControlMeasure: _this.riskDetail.newPreControlMeasure,
workPart: _this.riskDetail.workPart,
workContent: _this.riskDetail.workContent,
partName: _this.riskDetail.partName,
longitude: _this.riskDetail.longitude,
latitude: _this.riskDetail.latitude,
buildUnitId: _this.riskDetail.buildUnitId,
buildUnitName: _this.riskDetail.buildUnitName,
remark: _this.riskDetail.remark,
sectionId: _this.riskDetail.sectionId,
sectionName: _this.riskDetail.sectionName,
extendWorkPart: _this.riskDetail.extendWorkPart,
projectType: _this.riskDetail.projectType,
partIds: item,



siteDetail: _this.riskDetail.siteDetail,
projectDeptCode: _this.departId,
projectDeptName: _this.departName
}
let urls = 'youotech-saferisk/risk/discern/inventory/save'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
if(type == '1'){
_this.submit1()
}else{
if(_this.pageType == 'edit'){
_this.pageType = ''
_this.$store.commit('setQcAlive',false)
_this.back()
}else{
_this.$store.commit('setQcAlive',false)
_this.back()
}
}
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},
submit1 (){
let _this = this
_this.showLoading = true
let params = {
id: _this.riskDetail.id,
nodeId: _this.riskDetail.nodeId,
taskState: '1'
}
let urls = 'youotech-saferisk/risk/discern/inventory/check'
commonPost(urls,params,function(res){
_this.showLoading = false
if(res.code == 200){
if(_this.pageType == 'edit'){
_this.pageType = ''
_this.$store.commit('setQcAlive',false)
_this.back()
}else{
_this.$store.commit('setQcAlive',false)
_this.back()
}
}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

setPosition (){
let _this = this
_this.showLoading = true
AMap.plugin('AMap.Geolocation', function() {
var geolocation = new AMap.Geolocation({

lang: 'zh-cn'
});
geolocation.getCurrentPosition(function(status,result){
_this.showLoading = false
if(status=='complete'){
_this.riskDetail.partName = result.formattedAddress + '。'+ '经度：'+result.position.lng + ','+ '纬度：'+result.position.lat
_this.riskDetail.latitude = result.position.lat
_this.riskDetail.longitude = result.position.lng
_this.autoSize()
}else{
console.log(result.message)
_this.show1 = true
_this.text = result.message
}
});
});
},

peopPower (nodeId){//true 为you权限
if(this.isDetail){
this.canReview = false
this.canHandle = false
}else{
if(nodeId == '46'){//编辑
this.canReview = false
this.canHandle = true
}else if(nodeId == '47'){//监理审核
if(this.peopList.baseInfo.unitType == 'jl'){
this.canReview = true
this.canHandle = false
}else if(this.peopList.baseInfo.workTicketLevel == 21 && (this.peopList.baseInfo.postcode != '401' && this.peopList.baseInfo.postcode != '402')){
this.canReview = true
this.canHandle = false
}else{
this.canReview = false
this.canHandle = false
}
}else if(nodeId == '48'){//业主审核
if(this.peopList.baseInfo.postcode == '6' || this.peopList.baseInfo.postcode == '7'){
this.canReview = true
this.canHandle = false
}else if(this.peopList.baseInfo.postcode == '401' || this.peopList.baseInfo.postcode == '402'){
this.canReview = true
this.canHandle = false
}else{
this.canReview = false
this.canHandle = false
}
}else if(nodeId == '49'){//通过
this.canReview = false
this.canHandle = false
}else{
this.canReview = false
this.canHandle = false
}
}
},

getDetail (){
let _this = this
let params = {
id: _this.id
}
let urls = 'youotech-saferisk/risk/discern/inventory/detail'
commonGet(urls,params,function(res){
if(res.code == 200){
res.data.newPreControlMeasure = res.data.preControlMeasure
_this.riskDetail = res.data
_this.departName = res.data.projectDeptName
_this.departId = res.data.projectDeptCode



if(res.data.projectType == '1'){
_this.canChoose = true
}else{
if(_this.riskDetail.siteDetail == null || _this.riskDetail.siteDetail == ''){
_this.getSiteDetail(res.data.projectId,_this.departId)
}
}
_this.partId = res.data.partIds ? res.data.partIds.split(','): []
console.log(_this.riskDetail)
_this.getPartList(res.data.projectId,res.data.sectionId)

if(_this.riskDetail.preControlMeasure){
_this.riskDetail.preControlMeasure = _this.riskDetail.preControlMeasure.replace(/\n/g,',')
}
_this.peopPower(res.data.nodeId)

}else{
_this.show1 = true
_this.text = res.other.msg
}
})
},

getSiteDetail (projectId,departId){
let _this = this
let params = {}
let urls = 'pms/api/v1/'+projectId+'/departs/'+departId
commonGet(urls,params,function(res){
_this.riskDetail.siteDetail = res.address
})
},
nogn (){
this.show1 = true
this.text = '功能开发中...'
},
back (){
let _this = this
if(_this.pageType == 'edit'){
_this.$vux.confirm.show({

title: '提示',
content: '当前风险清册尚未保存，确定返回？',
onCancel () {
},
onConfirm () {
_this.$store.commit('setShowTab',true)
_this.$router.go(-1)
}
})
}else{
_this.$store.commit('setShowTab',true)
_this.$router.go(-1)
}

}
},









}



